/* ── Subagent API client ─────────────────────────────────────────────── */
/* Typed client for the /api/subagents/* endpoints and SSE streaming. */

import { api } from './client';

export interface WorkItem {
  goal: string;
  agentId?: string;
  restrictedTools?: string[];
  context?: string;
}

export interface SpawnRequest {
  workItems: WorkItem[];
  mode: 'auto' | 'proposed' | 'negotiated';
}

export interface SubagentInfo {
  taskId: string;
  agentId: string;
  goal: string;
  status: 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'recovered';
  result?: string;
  error?: string;
  startedAt: number;
  finishedAt?: number;
  elapsed: number;
}

export interface SpawnResult {
  status: string;
  total?: number;
  succeeded?: number;
  failed?: number;
  results?: SubagentInfo[];
  proposalId?: string;
  message?: string;
}

export interface SubagentEvent {
  type: string;
  taskId?: string;
  agentId?: string;
  goal?: string;
  content?: string;
  [key: string]: unknown;
}

/**
 * Subscribe to sub-agent SSE events for a session.
 * Returns an unsubscribe function.
 */
export function subscribeToSubagentEvents(
  sessionId: string,
  onEvent: (event: SubagentEvent) => void,
): () => void {
  const url = `/api/subagents/stream?sessionId=${encodeURIComponent(sessionId)}`;
  const source = new EventSource(url);

  source.onmessage = (msg: MessageEvent) => {
    try {
      const data = JSON.parse(msg.data) as SubagentEvent;
      onEvent(data);
    } catch {
      // ignore parse errors
    }
  };

  source.onerror = () => {
    // EventSource auto-reconnects
  };

  return () => {
    source.close();
  };
}

/** List active sub-agents for a session. */
export async function listActive(sessionId?: string): Promise<SubagentInfo[]> {
  const params = sessionId ? `?sessionId=${encodeURIComponent(sessionId)}` : '';
  const res = await api.get<{ agents: SubagentInfo[] }>(`/api/subagents/active${params}`);
  return res.agents;
}

/** Spawn one or more sub-agents. */
export async function spawn(request: SpawnRequest): Promise<SpawnResult> {
  return api.post<SpawnResult>('/api/subagents/spawn', request);
}

/** Terminate a running sub-agent by task ID. */
export async function terminate(taskId: string): Promise<{ status: string }> {
  return api.post<{ status: string }>(`/api/subagents/${encodeURIComponent(taskId)}/terminate`);
}

/** Approve or reject a proposed sub-agent breakdown. */
export async function proposeBreakdown(
  proposalId: string,
  approved: boolean = true,
): Promise<SpawnResult> {
  return api.post<SpawnResult>('/api/subagents/propose-breakdown', {
    proposalId,
    approved,
  });
}

/* ── AgentTree ─────────────────────────────────────────────────────────── */
/* Hierarchical view of sub-agent jobs for a session. Driven by the        */
/* /api/agents/tree endpoint.                                               */

import { useEffect, useState } from 'react';
import { ChevronRight, ChevronDown, Bot, Loader2, Check, AlertTriangle, StopCircle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';

export type AgentNode = {
  id: string;
  parentId: string | null;
  sessionId: string | null;
  agentId: string;
  parentAgentId: string | null;
  depth: number;
  task: string;
  status: 'running' | 'completed' | 'failed' | 'blocked';
  scope: string | null;
  startedAt: string;
  updatedAt: string;
  completedAt: string | null;
  resultSummary: string | null;
};

type Subtree = { root: AgentNode; children: Record<string, Subtree> };

type TreeResponse = {
  root: AgentNode;
  children: Record<string, Subtree>;
};

type Props = {
  rootId: string | null;
  maxDepth?: number;
  onSelect?: (node: AgentNode) => void;
};

async function fetchTree(rootId: string, maxDepth: number): Promise<TreeResponse | null> {
  try {
    const r = await fetch(`/api/agents/tree?root=${encodeURIComponent(rootId)}&maxDepth=${maxDepth}`);
    if (!r.ok) return null;
    return r.json();
  } catch (_) {
    return null;
  }
}

const STATUS_BADGE: Record<AgentNode['status'], { label: string; Icon: typeof Loader2; cls: string }> = {
  running:   { label: 'running',   Icon: Loader2,     cls: 'border-info/40 text-info' },
  completed: { label: 'completed', Icon: Check,       cls: 'border-success/40 text-success' },
  failed:    { label: 'failed',    Icon: AlertTriangle, cls: 'border-danger/40 text-danger' },
  blocked:   { label: 'blocked',   Icon: StopCircle,  cls: 'border-warning/40 text-warning' },
};

export function AgentTree({ rootId, maxDepth = 4, onSelect }: Props) {
  const [tree, setTree] = useState<TreeResponse | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!rootId) {
      setTree(null);
      return;
    }
    let cancelled = false;
    const tick = async () => {
      setLoading(true);
      const next = await fetchTree(rootId, maxDepth);
      if (cancelled) return;
      setTree(next);
      setLoading(false);
    };
    void tick();
    const t = setInterval(() => { void tick(); }, 3000);
    return () => {
      cancelled = true;
      clearInterval(t);
    };
  }, [rootId, maxDepth]);

  if (!rootId) return null;
  if (loading && !tree) return <div className="text-xs text-muted-foreground p-3">Loading agent tree…</div>;
  if (!tree) return <div className="text-xs text-muted-foreground p-3">No agent tree available.</div>;

  return (
    <div className="text-xs" data-testid="agent-tree">
      <TreeNode node={tree.root} childrenMap={tree.children} depth={0} onSelect={onSelect} defaultOpen />
    </div>
  );
}

function TreeNode({
  node,
  childrenMap,
  depth,
  onSelect,
  defaultOpen = false,
}: {
  node: AgentNode;
  childrenMap: Record<string, Subtree>;
  depth: number;
  onSelect?: (n: AgentNode) => void;
  defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  const childIds = Object.keys(childrenMap);
  const hasChildren = childIds.length > 0;
  const badge = STATUS_BADGE[node.status] || STATUS_BADGE.running;
  const Icon = badge.Icon;

  return (
    <div className="space-y-0.5">
      <div
        className={cn(
          'group flex items-start gap-2 rounded-md px-2 py-1.5 hover:bg-accent/30 cursor-pointer',
          depth === 0 && 'bg-accent/10'
        )}
        onClick={() => onSelect?.(node)}
        data-status={node.status}
      >
        <button
          type="button"
          className="mt-0.5 text-muted-foreground hover:text-foreground"
          onClick={(e) => {
            e.stopPropagation();
            setOpen((o) => !o);
          }}
          aria-label={open ? 'Collapse' : 'Expand'}
        >
          {hasChildren ? (
            open ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />
          ) : (
            <span className="inline-block w-3.5" />
          )}
        </button>
        <Bot className="mt-0.5 h-3.5 w-3.5 text-muted-foreground flex-none" />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="font-medium truncate">{node.agentId}</span>
            <Badge variant="outline" className={cn('text-[9px]', badge.cls)}>
              {badge.label}
            </Badge>
            <span className="text-[9px] text-muted-foreground/60">d{node.depth}</span>
            {node.scope && <span className="text-[9px] text-muted-foreground/60">· {node.scope}</span>}
          </div>
          <p className="text-[10px] text-muted-foreground/80 line-clamp-2">{node.task}</p>
        </div>
        <Icon className={cn('h-3.5 w-3.5 flex-none', node.status === 'running' && 'animate-spin')} />
      </div>
      {open && hasChildren && (
        <div className="ml-3 border-l border-border/40 pl-2 space-y-0.5">
          {childIds.map((cid) => (
            <TreeNode
              key={cid}
              node={childrenMap[cid].root}
              childrenMap={childrenMap[cid].children}
              depth={depth + 1}
              onSelect={onSelect}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export default AgentTree;

import { useEffect, useState } from 'react';
import { AlertCircle, Check, CheckCircle2, CircleDot, Code2, Loader2, FileSearch } from 'lucide-react';
import { cn } from '@/lib/utils';
import { DisclosureRow } from '@/components/chat/DisclosureRow';
import { ToolIcon } from '@/components/ui/ToolIcon';
import { FileIcon } from '@/components/ui/FileIcon';
import { DiffView } from '@/components/chat/DiffView';
import { confirmWorkbenchMutation } from '@/api/workbench';
import { visibleProgress, type ProgressEntry } from '@/lib/tool-progress';
import { getToolLabel } from '@/lib/tool-labels';
import { formatToolContext, formatToolResult, formatToolError, type FormattedContext } from '@/lib/tool-context-format';
import { ProviderSetupWidget } from '@/components/chat/ProviderSetupWidget';

/**
 * Extract a filename hint from a tool's JSON context (best-effort).
 * Returns null if the context isn't JSON or no filename-shaped key is present.
 */
function extractFilename(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (typeof parsed === 'string') return parsed;
    for (const key of ['filePath', 'file_path', 'path', 'filename', 'file', 'filepath', 'notebook_path', 'target_file']) {
      const v = parsed[key];
      if (typeof v === 'string' && v.length > 0) return v;
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Best-effort extraction of the actual command string for run_command tools.
 * The workbench stores tool input as a JSON-encoded `context` string, so
 * we look for an obvious `command` (or `cmd` / `shell_command`) field.
 */
function extractCommand(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (typeof parsed === 'string') return parsed;
    if (parsed && typeof parsed === 'object') {
      for (const key of ['command', 'cmd', 'shell_command', 'shellCommand', 'script']) {
        const v = (parsed as Record<string, unknown>)[key];
        if (typeof v === 'string' && v.length > 0) return v;
      }
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Best-effort extraction of the agentId parameter from a tool's context.
 */
function extractAgentId(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (parsed && typeof parsed === 'object') {
      for (const key of ['agentId', 'agent', 'subagentType']) {
        const v = (parsed as Record<string, unknown>)[key];
        if (typeof v === 'string' && v.length > 0) return v;
      }
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Format milliseconds to MM:SS format.
 */
function formatTimer(ms: number): string {
  const totalSeconds = Math.floor(Math.max(0, ms) / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  const pad = (num: number) => String(num).padStart(2, '0');
  return `${pad(minutes)}:${pad(seconds)}`;
}

// Above this length the per-character shimmer animation becomes visually
// noisy and slow. Used to decide between the animated "thinking-text" path
// and the plain monospace fallback.
const LONG_LABEL_THRESHOLD = 40;
function isLongLabel(label: string): boolean {
  return label.length > LONG_LABEL_THRESHOLD;
}

/**
 * Best-effort extraction of diff inputs from a tool's args / result.
 * Returns a payload compatible with <DiffView> props.
 */
function extractDiffData(tool: { context?: string; result?: unknown; name?: string }): {
  diff?: string;
  oldContent?: string;
  newContent?: string;
} | null {
  const isEditLike = /^(write_file|edit_file|replace_file|apply_patch|create_file|str_replace|@write_file|@edit_file|@replace_file|@apply_patch|@create_file|@str_replace)/i.test(
    (tool.name || '').replace(/^@/, '')
  );
  if (!isEditLike) return null;

  // 1) Pre-formatted diff (most common — workbench already computes it)
  if (tool.context && typeof tool.context === 'string' && /^[+\-@]/.test(tool.context.trim())) {
    // The context itself looks like a diff
    return { diff: tool.context };
  }
  if (typeof (tool as { inlineDiff?: string }).inlineDiff === 'string') {
    return { diff: (tool as { inlineDiff?: string }).inlineDiff };
  }

  // 2) Inspect args and result for old/new pairs
  let args: Record<string, unknown> = {};
  if (tool.context) {
    try { args = JSON.parse(tool.context) as Record<string, unknown>; } catch { /* ignore */ }
  }
  const result = (tool as { result?: unknown }).result;

  // Result: { diff: '...' } or { patch: '...' } or the result itself is a string
  if (typeof result === 'string' && (result.includes('--- ') || result.includes('+++ ') || result.startsWith('@@'))) {
    return { diff: result };
  }
  if (result && typeof result === 'object') {
    const r = result as Record<string, unknown>;
    if (typeof r.diff === 'string') return { diff: r.diff };
    if (typeof r.patch === 'string') return { diff: r.patch };
    if (typeof r.unifiedDiff === 'string') return { diff: r.unifiedDiff };
    if (typeof r.old === 'string' && typeof r.new === 'string') {
      return { oldContent: r.old, newContent: r.new };
    }
    if (typeof r.oldContent === 'string' && typeof r.newContent === 'string') {
      return { oldContent: r.oldContent, newContent: r.newContent };
    }
  }

  // 3) Args: { old_string, new_string } / { find, replace } / { patch } / { content } (no old → all added)
  const pick = (...keys: string[]) => {
    for (const k of keys) {
      const v = args[k];
      if (typeof v === 'string' && v.length > 0) return v;
    }
    return undefined;
  };
  const oldString = pick('old_string', 'find', 'old', 'oldContent');
  const newString = pick('new_string', 'replace', 'new', 'newContent', 'content', 'patch');
  if (oldString !== undefined && newString !== undefined) {
    return { oldContent: oldString, newContent: newString };
  }
  if (newString !== undefined) {
    // write_file with no old → show as all-added
    return { oldContent: '', newContent: newString };
  }

  return null;
}

export interface ToolEntry {
  id: string;
  name: string;
  context?: string;
  preview?: string;
  summary?: string;
  error?: string;
  inlineDiff?: string;
  status: 'running' | 'done' | 'error';
  duration?: number;
  startedAt?: number;
  pendingApproval?: {
    message?: string;
    detail?: string;
    confirmationToken?: string;
  };
  /** For web_search: structured search hits to render as linked list */
  searchHits?: Array<{ title: string; url: string; snippet?: string }>;
}

/**
 * ToolCallItem — renders one tool call like the Thinking disclosure.
 *
 * Uses DisclosureRow + char-glow animation (thinking-text) instead of
 * a bordered card. The tool name animates while running, same as the
 * "Thinking" label in ThinkingDisclosure.
 */
export function ToolCallItem({
  tool,
  progress,
  agentIdOverride,
}: {
  tool: ToolEntry;
  /** Optional live "Reading… / Read" sub-list emitted by the workbench. */
  progress?: ReadonlyArray<ProgressEntry>;
  agentIdOverride?: string;
}) {
  const [userOverride, setUserOverride] = useState<boolean | null>(null);
  const open = userOverride ?? tool.status === 'error';

  const [mountedAt] = useState(() => Date.now());
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    if (tool.status !== 'running') return;
    const id = window.setInterval(() => setNow(() => Date.now()), 500);
    return () => window.clearInterval(id);
  }, [tool.status]);

  let startedAtMs: number | undefined = undefined;
  if (tool.startedAt) {
    if (typeof tool.startedAt === 'number') {
      startedAtMs = tool.startedAt;
    } else if (typeof tool.startedAt === 'string') {
      const parsedNum = Number(tool.startedAt);
      if (!isNaN(parsedNum)) {
        startedAtMs = parsedNum;
      } else {
        const parsedDate = new Date(tool.startedAt).getTime();
        if (!isNaN(parsedDate)) {
          startedAtMs = parsedDate;
        }
      }
    } else if ((tool.startedAt as unknown) instanceof Date) {
      startedAtMs = (tool.startedAt as Date).getTime();
    }
  }

  if (tool.status === 'running' && (!startedAtMs || isNaN(startedAtMs))) {
    startedAtMs = mountedAt;
  }

  const hasTimestamps = tool.duration !== undefined || (tool.status === 'running' && startedAtMs !== undefined);
  const elapsed = hasTimestamps
    ? tool.duration ?? (startedAtMs ? now - startedAtMs : undefined)
    : undefined;


  const hasBody = !!(
    tool.context || tool.preview || tool.summary || tool.error || tool.inlineDiff || tool.searchHits || tool.pendingApproval
  );
  const [approvalStatus, setApprovalStatus] = useState<'idle' | 'confirming' | 'confirmed'>('idle');

  const isRunning = tool.status === 'running';
  // Safety timeout: if a tool has been running for > 120 seconds without a
  // result event, treat it as stalled — show a warning so the user knows
  // something went wrong rather than seeing an infinite spinner.
  const toolStalled = isRunning && startedAtMs !== undefined && (now - startedAtMs) > 120_000;
  const isCommand = tool.name.startsWith('@run_command') || tool.name.startsWith('run_command');
  // Strip the @ prefix that the workbench sometimes prepends so the icon
  // mapper matches the canonical tool name (e.g. "read_file" not "@read_file").
  const toolNameForIcon = tool.name.replace(/^@/, '');
  // For run_command tools, surface the actual command string inline so the
  // user can see what's being executed without expanding the disclosure —
  // especially important when the model runs a batch of commands and the
  // user is scanning the list. Truncate long commands with a tooltip that
  // shows the full text.
  const commandText = isCommand ? extractCommand(tool.context) : null;
  const filename = !isCommand ? extractFilename(tool.context) : null;
  const agentId = agentIdOverride || extractAgentId(tool.context);

  const label = getToolLabel(tool.name, {
    agentId: agentId ?? undefined,
    filename: filename ?? undefined,
    command: commandText ?? undefined,
    status: tool.status
  });
  const labelTitle = isCommand && commandText && commandText.length > 120
    ? commandText
    : isLongLabel(label) ? label : undefined;
  const displayLabel = (elapsed !== undefined && elapsed >= 100) ? `${label} · ${formatTimer(elapsed)}` : label;

  // Always-visible friendly context line: prefer the humanized summary from
  // formatToolContext; fall back to a single-line truncation of the raw
  // JSON args when no formatter matches.
  const friendlyCtx = tool.context ? formatToolContext(tool.name, tool.context) : null;
  const inlineContextText =
    friendlyCtx?.summary ??
    (tool.context && tool.context.length > 80
      ? `${tool.context.slice(0, 77).trimEnd()}…`
      : tool.context ?? null);

  return (
    <div className="text-xs text-muted-foreground w-full py-0.5" data-slot="tool-block">
      <DisclosureRow
        onToggle={hasBody ? () => setUserOverride(!open) : undefined}
        open={open && hasBody}
      >
        <span className="flex min-w-0 items-center gap-2">
          {filename ? (
            <FileIcon name={filename} size={14} className="shrink-0" />
          ) : (
            <ToolIcon name={toolNameForIcon} kind={isCommand ? 'command' : 'tool'} size={14} className="shrink-0" />
          )}
          <span
            className={cn(
              'text-xs font-medium leading-5 min-w-0 flex-1',
              isRunning && !isLongLabel(label) && 'text-foreground/85'
            )}
            title={labelTitle}
          >
            {isLongLabel(label) ? (
              // Long labels (typically a multi-flag shell command) bypass the
              // per-character shimmer animation: animating 100+ chars with a
              // 100ms stagger is visually noisy. Render as a plain monospace
              // span with a `title` tooltip for the full text.
              <span className="font-mono text-[11.5px] text-foreground/85 wrap-anywhere break-words">
                {displayLabel}
              </span>
            ) : (
              <span className="thinking-text">
                <span className="thinking-label">
                  {Array.from(displayLabel.replace(/ /g, '\u00A0')).map((ch, i) => (
                    <span
                      key={i}
                      className={cn('thinking-char', i === 0 && 'thinking-cap')}
                      style={{ animationDelay: `${i * 100}ms` }}
                    >
                      {ch}
                    </span>
                  ))}
                </span>
                {isRunning && (
                  <span className="thinking-dots">
                    <span className="dot" style={{ animationDelay: '0ms' }}>.</span>
                    <span className="dot" style={{ animationDelay: '200ms' }}>.</span>
                    <span className="dot" style={{ animationDelay: '400ms' }}>.</span>
                  </span>
                )}
              </span>
            )}
          </span>
          <span className="flex items-center gap-1.5 shrink-0 ml-auto pl-2">
            {toolStalled ? (
              <span className="inline-flex items-center gap-1">
                <AlertCircle className="size-3 text-warning" />
                <span className="tool-row-meta text-warning">stalled</span>
              </span>
            ) : tool.status === 'done' ? (
              <span className="inline-flex items-center gap-1">
                <span className="inline-block size-1.5 rounded-full bg-success" />
                <span className="tool-row-meta text-success">done</span>
              </span>
            ) : tool.status === 'error' ? (
              <span className="inline-flex items-center gap-1">
                <AlertCircle className="size-3 text-danger" />
                <span className="tool-row-meta text-danger">failed</span>
              </span>
            ) : tool.status === 'running' && tool.pendingApproval ? (
              <span className="inline-flex items-center gap-1">
                <CircleDot className="size-3 text-warning animate-pulse" />
                <span className="tool-row-meta text-warning">awaiting</span>
              </span>
            ) : null}
          </span>
        </span>
      </DisclosureRow>

      {inlineContextText && (
        <div
          className="tool-row-meta mt-0.5 text-muted-foreground/85 truncate"
          title={tool.context ?? inlineContextText}
        >
          {inlineContextText}
        </div>
      )}

      {open && hasBody && (
        <div className="mt-0.5 w-full min-w-0 max-w-full overflow-hidden wrap-anywhere pb-1">
          {/* For read-type tools (context_read, memory_search, read_file etc.)
              the raw JSON input is noise — skip it so the user sees what was
              actually read (the result/summary) when they expand the card. */}
          {tool.context && !tool.name.match(/context_read|memory_search|read_file|search/) && (
            <FormattedSection toolName={tool.name} label="context" raw={tool.context} format={formatToolContext} />
          )}

          {(() => {
            const visible = progress ? visibleProgress(progress) : [];
            const total = progress?.length ?? 0;
            const overflow = Math.max(0, total - visible.length);
            if (visible.length === 0) return null;
            return (
              <div className="my-1.5 space-y-0.5" aria-label="Tool progress" data-tool-progress>
                <div className="flex items-center gap-1 text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  <FileSearch size={10} />
                  <span>
                    {tool.status === 'running' ? 'Exploring' : 'Files'}
                  </span>
                </div>
                {visible.map((entry) => (
                  <div
                    key={entry.path}
                    className="flex items-center gap-1.5 text-[11px] truncate"
                    title={entry.path}
                  >
                    <span className="w-2.5 shrink-0 inline-flex justify-center">
                      {entry.status === 'reading' ? (
                        <Loader2 size={10} className="animate-spin text-info" />
                      ) : (
                        <Check size={10} className="text-muted-foreground/50" />
                      )}
                    </span>
                    <span
                      className={cn(
                        'truncate font-mono',
                        entry.status === 'reading' ? 'text-info italic' : 'text-muted-foreground/60 line-through'
                      )}
                    >
                      {entry.status === 'reading' ? 'Reading ' : 'Read '}
                      {entry.path}
                    </span>
                  </div>
                ))}
                {overflow > 0 && (
                  <div className="text-[10px] text-muted-foreground/50 italic pl-4">
                    + {overflow} more
                  </div>
                )}
              </div>
            );
          })()}

          {tool.preview && tool.status === 'running' && (
            <Section label="streaming">
              {tool.preview}
              <span className="inline-block w-1.5 h-3 align-middle bg-foreground/40 ml-0.5 animate-pulse" />
            </Section>
          )}

          {(() => {
            const diffData = extractDiffData(tool);
            return diffData ? (
              <Section label="diff">
                <DiffView
                  diff={diffData.diff}
                  oldContent={diffData.oldContent}
                  newContent={diffData.newContent}
                />
              </Section>
            ) : null;
          })()}

          {tool.searchHits && tool.searchHits.length > 0 && (
            <Section label="results">
              <ol className="m-0 grid list-none gap-3 p-0">
                {tool.searchHits.map((hit, i) => (
                  <li key={i} className="grid min-w-0 gap-1">
                    <div className="flex items-start gap-2">
                      {hit.url && (
                        <img
                          src={`https://www.google.com/s2/favicons?domain=${new URL(hit.url).hostname}&sz=16`}
                          alt=""
                          className="size-4 shrink-0 mt-0.5 rounded"
                          width={16}
                          height={16}
                          loading="lazy"
                        />
                      )}
                      <div className="min-w-0 flex-1">
                        {hit.url ? (
                          <a
                            href={hit.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-xs font-medium text-primary hover:underline truncate block"
                          >
                            {hit.title || new URL(hit.url).hostname}
                          </a>
                        ) : (
                          <span className="text-xs font-medium text-foreground/90">{hit.title}</span>
                        )}
                        {hit.url && (
                          <p className="text-[10px] text-muted-foreground/60 truncate mt-0.5">
                            {hit.url}
                          </p>
                        )}
                      </div>
                    </div>
                    {hit.snippet && (
                      <p className="text-[10px] text-muted-foreground line-clamp-3 m-0 pl-6">{hit.snippet}</p>
                    )}
                  </li>
                ))}
              </ol>
            </Section>
          )}

          {tool.summary && !tool.searchHits && !tool.providerSetup && (
            <FormattedResultSection toolName={tool.name} raw={tool.summary} />
          )}

          {tool.providerSetup && (
            <ProviderSetupWidget setup={tool.providerSetup} />
          )}

          {tool.error && (
            <FormattedErrorSection toolName={tool.name} raw={tool.error} />
          )}

          {tool.pendingApproval && (
            <div className="mt-2 flex flex-col gap-2 rounded-md border border-primary/30 bg-primary/10 p-2">
              <div className="text-xs text-foreground/90">
                {tool.pendingApproval.message || 'This change needs approval before it can run.'}
              </div>
              {tool.pendingApproval.detail && (
                <div className="text-[11px] font-mono text-muted-foreground wrap-anywhere">
                  {tool.pendingApproval.detail}
                </div>
              )}
              <button
                type="button"
                disabled={approvalStatus !== 'idle'}
                className="h-7 rounded-md bg-primary px-3 text-xs font-medium text-primary-foreground disabled:opacity-60"
                onClick={() => {
                  const token = tool.pendingApproval?.confirmationToken;
                  if (!token) return;
                  setApprovalStatus('confirming');
                  void confirmWorkbenchMutation(token, {
                    onText: ({ content }) => {
                      tool.summary = `${tool.summary || ''}\n${typeof content === 'string' ? content : JSON.stringify(content ?? '')}`.trim();
                    },
                    onToolUse: ({ id: _id, name, input }) => {
                      tool.summary = `${tool.summary || ''}\nStarted ${name}: ${JSON.stringify(input || {})}`.trim();
                    },
                    onToolResult: ({ content }) => {
                      tool.summary = `${tool.summary || ''}\n${typeof content === 'string' ? content : JSON.stringify(content ?? '')}`.trim();
                    },
                    onError: ({ message }) => {
                      tool.error = message;
                    },
                    onDone: () => {
                      setApprovalStatus('confirmed');
                    },
                  });
                }}
              >
                {approvalStatus === 'confirming' ? 'Approving…' : 'Approve'}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Section({
  label,
  children,
  tone,
}: {
  label: string;
  children: React.ReactNode;
  tone?: 'error';
}) {
  return (
    <div className="flex gap-3 mt-1.5">
      <span
        className={`text-[10px] shrink-0 w-16 pt-0.5 ${
          tone === 'error' ? 'text-destructive' : 'text-muted-foreground/60'
        }`}
      >
        {label}
      </span>
      <div className="flex-1 min-w-0 text-muted-foreground">{children}</div>
    </div>
  );
}

/**
 * Render a section that defaults to a friendly summary line, with a small
 * "Show raw" chevron that reveals the underlying JSON in a `<pre>` block.
 * `format` is one of `formatToolContext` / `formatToolResult`; if it returns
 * null we fall back to rendering the raw text verbatim.
 *
 * The optional `kind` on the formatted result drives a small status icon
 * (`✅` for success, default for neutral) so success/error states are
 * visually obvious at a glance.
 */
function FormattedSection({
  toolName,
  label,
  raw,
  format,
  tone,
}: {
  toolName: string;
  label: string;
  raw: string;
  format: (toolName: string, raw: string) => FormattedContext | null;
  tone?: 'error';
}) {
  const formatted = format(toolName, raw);
  const summary = formatted?.summary ?? raw;
  const showRawToggle = !!formatted && formatted.summary !== formatted.raw;
  const [showRaw, setShowRaw] = useState(false);

  const isSuccess = formatted?.kind === 'success';
  const summaryClass = isSuccess
    ? 'text-success'
    : 'text-foreground/90';

  return (
    <div className="flex gap-3 mt-1.5">
      <span
        className={`text-[10px] shrink-0 w-16 pt-0.5 ${
          tone === 'error' ? 'text-destructive' : 'text-muted-foreground/60'
        }`}
      >
        {label}
      </span>
      <div className="flex-1 min-w-0 text-muted-foreground">
        <span className={cn('inline-flex items-baseline gap-1.5 whitespace-pre-wrap break-words', summaryClass)}>
          {isSuccess && <CheckCircle2 className="inline-block size-3 shrink-0 self-center text-success" />}
          <span>{summary}</span>
        </span>
        {showRawToggle && (
          <button
            type="button"
            onClick={() => setShowRaw(v => !v)}
            className="ml-2 inline-flex items-center gap-0.5 text-[10px] text-muted-foreground/60 hover:text-muted-foreground transition-colors align-baseline"
            title={showRaw ? 'Hide raw JSON' : 'Show raw JSON'}
          >
            <Code2 className="size-2.5" />
            {showRaw ? 'Hide raw' : 'Show raw'}
          </button>
        )}
        {showRaw && showRawToggle && (
          <pre className="mt-1 max-h-60 overflow-auto rounded-md border border-white/[0.06] bg-black/30 px-2 py-1.5 text-[11px] leading-relaxed font-mono whitespace-pre-wrap wrap-break-word text-muted-foreground/85">
            {tryPrettyJson(raw)}
          </pre>
        )}
      </div>
    </div>
  );
}

/**
 * Specialisation of FormattedSection for the `result` line — only reformats
 * when the result is a JSON object in a known shape, otherwise falls back to
 * the existing plain-text rendering.
 */
function FormattedResultSection({ toolName, raw }: { toolName: string; raw: string }) {
  const formatted = formatToolResult(toolName, raw);
  // If the formatter doesn't recognise the shape, render the raw text the
  // way the original code did — preserving whitespace and styling.
  if (!formatted) {
    return (
      <Section label="result">
        <span className="text-foreground/90 whitespace-pre-wrap break-words">{raw}</span>
      </Section>
    );
  }
  return <FormattedSection toolName={toolName} label="result" raw={raw} format={formatToolResult} />;
}

/**
 * Prominent error block — rendered when `tool.error` is present. Uses
 * `formatToolError` to parse structured error payloads (JSON with a
 * `message` field, etc.) into a single clean message + optional detail
 * line, then surfaces the raw text behind a "Show raw" toggle.
 */
function FormattedErrorSection({ toolName, raw }: { toolName: string; raw: string }) {
  const formatted = formatToolError(toolName, raw);
  const message = formatted?.message ?? raw.trim();
  const detail = formatted?.detail;
  const showRawToggle = !!formatted && formatted.raw !== message;
  const [showRaw, setShowRaw] = useState(false);

  return (
    <div className="mt-1.5 flex gap-3">
      <span className="text-[10px] shrink-0 w-16 pt-0.5 text-destructive">error</span>
      <div className="flex-1 min-w-0">
        <div className="rounded-md border border-destructive/30 bg-destructive/10 px-2.5 py-1.5 text-[11.5px] leading-relaxed">
          <div className="flex items-start gap-1.5">
            <AlertCircle className="size-3 shrink-0 mt-0.5 text-destructive" />
            <div className="min-w-0 flex-1">
              <div className="text-destructive whitespace-pre-wrap break-words font-medium">
                {message}
              </div>
              {detail && (
                <div className="mt-0.5 text-destructive/80 text-[11px] font-mono whitespace-pre-wrap break-words">
                  {detail}
                </div>
              )}
            </div>
          </div>
          {showRawToggle && (
            <div className="mt-1.5 flex items-center gap-2">
              <button
                type="button"
                onClick={() => setShowRaw(v => !v)}
                className="inline-flex items-center gap-0.5 text-[10px] text-destructive/70 hover:text-destructive transition-colors"
                title={showRaw ? 'Hide raw error' : 'Show raw error'}
              >
                <Code2 className="size-2.5" />
                {showRaw ? 'Hide raw' : 'Show raw'}
              </button>
              {showRaw && (
                <pre className="flex-1 max-h-40 overflow-auto rounded border border-destructive/20 bg-black/30 px-2 py-1 text-[10.5px] leading-relaxed font-mono whitespace-pre-wrap wrap-break-word text-muted-foreground/85">
                  {tryPrettyJson(raw)}
                </pre>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function tryPrettyJson(raw: string): string {
  try {
    const parsed = JSON.parse(raw);
    return JSON.stringify(parsed, null, 2);
  } catch {
    return raw;
  }
}

/* ── ApprovalBanner ───────────────────────────────────────────────────── */
/* Session-level "awaiting approval" banner driven by /api/workbench/session/:id/status. */
/* Polls the endpoint every 2s; flips to a sticky banner when the server */
/* reports a pending critical mutation. Approve / Deny buttons POST to */
/* /api/workbench/confirm-mutation. */

import { useEffect, useMemo, useState } from 'react';
import { ShieldCheck, ShieldAlert, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

type SessionStatus = {
    sessionId: string;
    status: 'idle' | 'running' | 'awaiting_approval' | 'completed' | 'failed' | 'cancelled';
    pendingTool: string | null;
    pendingToken: string | null;
    pendingArgs: Record<string, unknown> | null;
    pendingCreatedAt: number | null;
    updatedAt: string | null;
    guardMode: 'plan' | 'ask' | 'full';
    approved: boolean;
};

type Props = {
    sessionId: string | null;
    pollIntervalMs?: number;
    onStatusChange?: (status: SessionStatus | null) => void;
};

async function fetchStatus(sessionId: string): Promise<SessionStatus | null> {
    try {
        const r = await fetch(`/api/workbench/session/${encodeURIComponent(sessionId)}/status`, { credentials: 'same-origin' });
        if (!r.ok) return null;
        return r.json() as Promise<SessionStatus>;
    } catch {
        return null;
    }
}

async function postDecision(sessionId: string, token: string, reject: boolean) {
    const r = await fetch('/api/workbench/confirm-mutation', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'same-origin',
        body: JSON.stringify({ sessionId, token, reject })
    });
    if (!r.ok) {
        const text = await r.text().catch(() => '');
        throw new Error(text || `Approval API returned ${r.status}`);
    }
    return r.json();
}

function summarizeTool(toolName: string | null, args: Record<string, unknown> | null): string {
    if (!toolName) return 'The model is waiting for your approval.';
    if (!args) return `Tool: ${toolName}`;
    const keys = Object.keys(args).filter((k) => k !== 'confirmed' && k !== 'reReadFirst');
    const first = keys[0];
    if (first) {
        const value = typeof args[first] === 'string' ? args[first] : JSON.stringify(args[first] ?? '');
        return `Tool: ${toolName} — ${first}: ${value.slice(0, 80)}`;
    }
    return `Tool: ${toolName}`;
}

export function ApprovalBanner({ sessionId, pollIntervalMs = 2000, onStatusChange }: Props) {
    const [status, setStatus] = useState<SessionStatus | null>(null);
    const [deciding, setDeciding] = useState<'approve' | 'reject' | null>(null);

    useEffect(() => {
        if (!sessionId) {
            setStatus(null);
            onStatusChange?.(null);
            return;
        }
        let cancelled = false;
        const tick = async () => {
            const next = await fetchStatus(sessionId);
            if (cancelled) return;
            setStatus(next);
            onStatusChange?.(next);
        };
        void tick();
        const t = setInterval(() => { void tick(); }, pollIntervalMs);
        return () => {
            cancelled = true;
            clearInterval(t);
        };
    }, [sessionId, pollIntervalMs, onStatusChange]);

    const isAwaiting = status?.status === 'awaiting_approval' && !!status.pendingToken;
    const summary = useMemo(
        () => summarizeTool(status?.pendingTool ?? null, status?.pendingArgs ?? null),
        [status?.pendingTool, status?.pendingArgs]
    );

    const onApprove = async () => {
        if (!status?.pendingToken) return;
        setDeciding('approve');
        try {
            await postDecision(status.sessionId, status.pendingToken, false);
            toast.success('Approved — resuming the model');
        } catch (e) {
            toast.error(`Approval failed: ${(e as Error).message}`);
        } finally {
            setDeciding(null);
        }
    };

    const onReject = async () => {
        if (!status?.pendingToken) return;
        setDeciding('reject');
        try {
            await postDecision(status.sessionId, status.pendingToken, true);
            toast.message('Denied — the model will be told');
        } catch (e) {
            toast.error(`Denial failed: ${(e as Error).message}`);
        } finally {
            setDeciding(null);
        }
    };

    return (
        <AnimatePresence>
            {isAwaiting && (
                <motion.div
                    key="approval-banner"
                    initial={{ opacity: 0, y: -8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -8 }}
                    transition={{ duration: 0.18 }}
                    className={cn(
                        'mx-auto my-2 flex w-full max-w-3xl items-start gap-3 rounded-lg border px-4 py-3',
                        'border-warning/30 bg-warning/10 text-foreground'
                    )}
                    data-testid="approval-banner"
                    role="status"
                    aria-live="polite"
                >
                    <ShieldAlert className="mt-0.5 h-5 w-5 flex-none text-warning" />
                    <div className="flex-1 text-sm">
                        <div className="font-medium">Awaiting your approval</div>
                        <div className="text-warning/90">{summary}</div>
                        {status?.pendingArgs && (
                            <details className="mt-1 text-xs text-warning/80">
                                <summary className="cursor-pointer">View arguments</summary>
                                <pre className="mt-1 max-h-32 overflow-auto rounded bg-black/30 p-2 text-[11px]">
                                    {JSON.stringify(status.pendingArgs, null, 2)}
                                </pre>
                            </details>
                        )}
                    </div>
                    <div className="flex gap-2">
                        <Button
                            size="sm"
                            variant="outline"
                            onClick={() => { void onReject(); }}
                            disabled={!!deciding}
                            className="border-warning/40 text-warning hover:bg-warning/20"
                        >
                            <X className="mr-1 h-3.5 w-3.5" />
                            Deny
                        </Button>
                        <Button
                            size="sm"
                            onClick={() => { void onApprove(); }}
                            disabled={!!deciding}
                            className="bg-warning text-black hover:bg-warning/90"
                        >
                            <ShieldCheck className="mr-1 h-3.5 w-3.5" />
                            {deciding === 'approve' ? 'Approving…' : 'Approve'}
                        </Button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

export type { SessionStatus };
export default ApprovalBanner;

/* eslint-disable react-refresh/only-export-components */

import { useState, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Search, Check } from 'lucide-react';
import { modelDisplayParts, getModelDisplayName } from '@/sections/chat/ChatThread';
import { cn } from '@/lib/utils';

interface ModelItem {
  id: string;
  name: string;
  provider: string;
  contextWindow: number;
  isFree?: boolean;
  supportsReasoning?: boolean;
  supportsThinking?: boolean;
}

interface Props {
  open: boolean;
  onClose: () => void;
  models: ModelItem[];
  loading: boolean;
  hiddenModels: Set<string>;
  onToggleModel: (modelId: string) => void;
  onNavigate: (path: string) => void;
  onRefreshModels?: () => void;
}

const STORAGE_KEY = 'august-hidden-models';

export function loadHiddenModels(): Set<string> {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return new Set(JSON.parse(saved));
  } catch { /* silent */ }
  return new Set();
}

export function saveHiddenModels(hidden: Set<string>) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify([...hidden]));
}

export function ModelVisibilityModal({ open, onClose, models, loading, hiddenModels, onToggleModel, onNavigate, onRefreshModels }: Props) {
  const [search, setSearch] = useState('');
  const [internalLoading, setInternalLoading] = useState(false);

  useEffect(() => {
    if (open && models.length === 0) {
      setInternalLoading(true);
      onRefreshModels?.();
    }
  }, [open, models.length, onRefreshModels]);

  useEffect(() => {
    if (models.length > 0) setInternalLoading(false);
  }, [models.length]);

  const isLoading = loading || internalLoading;

  const grouped = useMemo(() => {
    const q = search.trim().toLowerCase();
    const filtered = q
      ? models.filter(m =>
          m.id.toLowerCase().includes(q) ||
          getModelDisplayName(m.id).toLowerCase().includes(q) ||
          m.provider.toLowerCase().includes(q)
        )
      : models;

    const groups: Record<string, ModelItem[]> = {};
    filtered.forEach(m => {
      if (!groups[m.provider]) groups[m.provider] = [];
      groups[m.provider].push(m);
    });

    return Object.entries(groups).sort(([a], [b]) => a.localeCompare(b));
  }, [models, search]);

  if (!open) return null;

  return (
    <AnimatePresence>
      {open && (
        <>
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm"
            onClick={onClose}
          />
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 10 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 10 }}
            transition={{ duration: 0.15, ease: [0.16, 1, 0.3, 1] }}
            className="fixed left-1/2 top-[15%] z-50 -translate-x-1/2 w-[420px] h-[500px] bg-popover rounded-xl shadow-2xl flex flex-col overflow-hidden"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-border/30">
              <h2 className="text-sm font-semibold text-foreground">Edit Models</h2>
              <button onClick={onClose} className="p-1 hover:bg-white/10 rounded text-muted-foreground hover:text-foreground transition">
                <X className="size-4" />
              </button>
            </div>

            {/* Search */}
            <div className="px-4 py-2 border-b border-border/20">
              <div className="relative">
                <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-3 text-muted-foreground/50" />
                <input
                  autoFocus
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  placeholder="Search models..."
                  className="w-full pl-8 pr-3 py-1.5 text-xs bg-muted/30 rounded-md border-none outline-none text-foreground placeholder:text-muted-foreground/50"
                />
              </div>
            </div>

            {/* Model list */}
            <div className="flex-1 overflow-y-auto px-2 py-2 min-h-0">
              {isLoading && models.length === 0 ? (
                <div className="space-y-2 px-2 py-3">
                  {Array.from({ length: 8 }).map((_, i) => (
                    <div key={i} className="flex items-center gap-2.5">
                      <div className="size-4 rounded bg-muted/30 animate-pulse" />
                      <div className={cn("h-3 rounded bg-muted/30 animate-pulse", i % 3 === 0 ? 'w-3/4' : i % 3 === 1 ? 'w-1/2' : 'w-2/3')} />
                    </div>
                  ))}
                </div>
              ) : grouped.length === 0 ? (
                <div className="py-8 text-center text-xs text-muted-foreground">
                  {search ? 'No models match your search' : 'No models available'}
                </div>
              ) : (
                grouped.map(([provider, providerModels]) => (
                  <div key={provider} className="mb-3">
                    <div className="px-2 py-1 text-[10px] uppercase tracking-widest text-muted-foreground/50 font-semibold">
                      {provider}
                    </div>
                    {providerModels.map(m => {
                      const { name, tag } = modelDisplayParts(m.id);
                      const isVisible = !hiddenModels.has(m.id);
                      return (
                        <button
                          key={m.id}
                          onClick={() => onToggleModel(m.id)}
                          className={cn(
                            'w-full flex items-center gap-2.5 px-2.5 py-1.5 rounded-md text-left transition',
                            isVisible ? 'hover:bg-white/5' : 'opacity-40 hover:opacity-60 hover:bg-white/5'
                          )}
                        >
                          <span className={cn(
                            'size-4 rounded flex items-center justify-center shrink-0 border transition-colors',
                            isVisible
                              ? 'bg-primary border-primary text-primary-foreground'
                              : 'border-muted-foreground/30 bg-transparent'
                          )}>
                            {isVisible && <Check className="size-2.5" />}
                          </span>
                          <span className="truncate flex-1 text-xs font-sans">
                            {name}
                            {tag && <span className="ml-1 text-muted-foreground/50 text-[10px]">{tag}</span>}
                          </span>
                          <span className="text-[10px] text-muted-foreground/40 font-mono shrink-0">
                            {m.isFree ? 'free' : ''}
                          </span>
                        </button>
                      );
                    })}
                  </div>
                ))
              )}
            </div>

            {/* Footer */}
            <div className="px-4 py-2.5 border-t border-border/30">
              <button
                onClick={() => { onClose(); onNavigate('/settings'); }}
                className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition"
              >
                <Plus className="size-3" />
                Add provider
              </button>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

/* ── Provider Onboarding Modal ────────────────────────────────────────── */
/* First-launch modal shown when the providers list is empty and the user
   has not previously skipped onboarding. Offers three paths:
   1) "Set Up a Provider" — navigates to /settings/providers
   2) "Import Config" — paste JSON blob → POST /api/providers/import-config
   3) "Skip for now" — sets localStorage flag, modal won't show again. */

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useQueryClient } from '@tanstack/react-query';
import { Cloud, Upload, X } from 'lucide-react';
import { useProviderOnboardingState } from '@/hooks/useProviderOnboardingState';
import { providersApi } from '@/api/providers';
import { Backdrop } from '@/components/overlays/Backdrop';

export function ProviderOnboardingModal() {
  const { shouldShow, skip, isLoading } = useProviderOnboardingState();
  const navigate = useNavigate();
  const qc = useQueryClient();
  const [showImport, setShowImport] = useState(false);
  const [importJson, setImportJson] = useState('');
  const [importError, setImportError] = useState('');
  const [importing, setImporting] = useState(false);

  if (!shouldShow || isLoading) return null;

  const handleSetUpProvider = () => {
    void navigate('/settings/providers');
  };

  const handleImport = async () => {
    setImportError('');
    setImporting(true);
    try {
      const config = JSON.parse(importJson);
      await providersApi.importConfig(config);
      void qc.invalidateQueries({ queryKey: ['providers'] });
      void qc.invalidateQueries({ queryKey: ['aggregated-models'] });
      setShowImport(false);
      setImportJson('');
    } catch (e: unknown) {
      setImportError(
        e instanceof Error ? e.message : 'Invalid JSON or import failed.',
      );
    } finally {
      setImporting(false);
    }
  };

  return (
    <Backdrop onClose={skip}>
      <div
        className="relative w-full max-w-md rounded-2xl border border-white/[0.06] bg-card p-6 shadow-2xl"
        role="dialog"
        aria-modal="true"
        aria-label="Provider setup"
      >
        <button
          type="button"
          onClick={skip}
          className="absolute right-4 top-4 text-muted-foreground hover:text-foreground"
          aria-label="Close"
        >
          <X className="size-4" />
        </button>

        <div className="mb-6 text-center">
          <div className="mx-auto mb-3 flex size-12 items-center justify-center rounded-full bg-primary/10">
            <Cloud className="size-6 text-primary" />
          </div>
          <h2 className="text-lg font-semibold">Welcome to August</h2>
          <p className="mt-1 text-sm text-muted-foreground">
            Connect an AI provider to start chatting. You can add multiple
            providers and switch between them at any time.
          </p>
        </div>

        {showImport ? (
          <div className="space-y-3">
            <label className="block text-xs font-medium text-muted-foreground">
              Paste provider config JSON
            </label>
            <textarea
              value={importJson}
              onChange={(e) => setImportJson(e.target.value)}
              placeholder='{"name": "My Provider", "baseUrl": "https://...", "apiKey": "sk-..."}'
              rows={6}
              className="w-full rounded-lg border border-white/[0.06] bg-black/20 p-3 text-xs font-mono text-foreground placeholder:text-muted-foreground/40 focus:border-primary outline-none resize-none"
            />
            {importError && (
              <p className="text-xs text-destructive">{importError}</p>
            )}
            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={() => setShowImport(false)}
                className="flex-1 rounded-lg border border-white/[0.06] px-4 py-2 text-sm hover:bg-white/[0.06]"
              >
                Back
              </button>
              <button
                type="button"
                onClick={() => { void handleImport(); }}
                disabled={!importJson.trim() || importing}
                className="flex-1 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground hover:opacity-90 disabled:opacity-50"
              >
                {importing ? 'Importing…' : 'Import'}
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            <button
              type="button"
              onClick={handleSetUpProvider}
              className="flex w-full items-center gap-3 rounded-xl border border-white/[0.06] bg-black/20 px-4 py-3 text-left hover:bg-white/[0.06] transition-colors"
            >
              <Cloud className="size-5 text-primary shrink-0" />
              <div>
                <p className="text-sm font-medium">Set Up a Provider</p>
                <p className="text-xs text-muted-foreground">
                  Configure Anthropic, OpenAI, or any OpenAI-compatible endpoint
                </p>
              </div>
            </button>

            <button
              type="button"
              onClick={() => setShowImport(true)}
              className="flex w-full items-center gap-3 rounded-xl border border-white/[0.06] bg-black/20 px-4 py-3 text-left hover:bg-white/[0.06] transition-colors"
            >
              <Upload className="size-5 text-primary shrink-0" />
              <div>
                <p className="text-sm font-medium">Import Config</p>
                <p className="text-xs text-muted-foreground">
                  Paste a JSON configuration from clipboard or export
                </p>
              </div>
            </button>

            <button
              type="button"
              onClick={skip}
              className="flex w-full items-center justify-center rounded-xl px-4 py-2.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
            >
              Skip for now
            </button>
          </div>
        )}
      </div>
    </Backdrop>
  );
}

/* v4.4.3 — BrainIndicator: titlebar Brain icon + pulse dot + draggable +
 * resizable floating popup. ESC and click-outside no longer close — only the
 * × button (per user request). Position and size persist across reloads.
 *
 * IMPORTANT (v4.4.3 bug fix): the popup is rendered via createPortal to
 * document.body. The chat shell wraps content in framer-motion's
 * `<motion.div>` which applies `transform`, and that creates a
 * containing block for `position: fixed` — making the popup get trapped
 * inside the titlebar and render at the wrong offsets (off-screen on the
 * chat route but visible on routes that don't have motion.div ancestors).
 * Portaling to document.body lets fixed be viewport-relative. */
import { useCallback, useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { Brain, X, Activity, Heart, Sparkles } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { cn } from '@/lib/utils';
import {
  getBrainEvents,
  openBrainEventStream,
  type BrainEvent,
} from '@/api/api-client';
import { LearningTab } from '@/sections/brain/LearningTab';
import { SystemHealthTab } from '@/sections/brain/SystemHealthTab';
import { BrainActivityTab } from '@/sections/brain/BrainActivityTab';

interface BrainIndicatorProps {
  /** Optional initial unseen-event count (for tests + future bootstrap). */
  initialUnseen?: number;
}

type TabKey = 'activity' | 'learning' | 'health';

const STORAGE_KEY = 'august-brain-popup-state';
const DEFAULT_WIDTH = 520;
const DEFAULT_HEIGHT = 520;
const MIN_WIDTH = 380;
const MIN_HEIGHT = 320;
const MARGIN = 16; // padding from viewport edges

interface PopupState {
  width: number;
  height: number;
  x: number; // left in viewport coords
  y: number; // top in viewport coords
}

function loadState(): PopupState {
  if (typeof window === 'undefined') return defaultState();
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as Partial<PopupState>;
      if (
        typeof parsed.width === 'number' &&
        typeof parsed.height === 'number' &&
        typeof parsed.x === 'number' &&
        typeof parsed.y === 'number'
      ) {
        return clampState(parsed as PopupState);
      }
    }
  } catch {
    /* fall through */
  }
  return defaultState();
}

function defaultState(): PopupState {
  // Default: anchored top-right, just under the title bar (h-12 + 4px)
  return {
    width: DEFAULT_WIDTH,
    height: DEFAULT_HEIGHT,
    x: typeof window !== 'undefined' ? Math.max(MARGIN, window.innerWidth - DEFAULT_WIDTH - MARGIN) : 200,
    y: 64, // title bar (~48px) + 16px gap
  };
}

function clampState(s: PopupState): PopupState {
  const w = Math.max(MIN_WIDTH, Math.min(s.width, (typeof window !== 'undefined' ? window.innerWidth : 1200) - MARGIN * 2));
  const h = Math.max(MIN_HEIGHT, Math.min(s.height, (typeof window !== 'undefined' ? window.innerHeight : 800) - MARGIN * 2));
  const x = Math.max(MARGIN, Math.min(s.x, (typeof window !== 'undefined' ? window.innerWidth : 1200) - w - MARGIN));
  const y = Math.max(MARGIN, Math.min(s.y, (typeof window !== 'undefined' ? window.innerHeight : 800) - h - MARGIN));
  return { width: w, height: h, x, y };
}

export function BrainIndicator({ initialUnseen = 0 }: BrainIndicatorProps) {
  const [open, setOpen] = useState(false);
  const [tab, setTab] = useState<TabKey>('activity');
  const [unseen, setUnseen] = useState(initialUnseen);
  const [geom, setGeom] = useState<PopupState>(() => loadState());
  const geomRef = useRef<PopupState>(geom);
  geomRef.current = geom;

  // Pre-fetch recent events so the popup has content instantly
  useQuery({
    queryKey: ['brain-events'],
    queryFn: () => getBrainEvents(200),
    enabled: open,
  });

  // Always-on SSE so we can bump the unseen counter even when popup is closed
  useEffect(() => {
    const es = openBrainEventStream();
    es.onmessage = (ev: MessageEvent) => {
      try {
        const _event: BrainEvent = JSON.parse(ev.data);
        setUnseen((n) => n + 1);
      } catch {
        /* ignore malformed frames */
      }
    };
    return () => es.close();
  }, []);

  // Persist geometry when popup closes
  const persistGeom = useCallback(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(geomRef.current));
    } catch {
      /* swallow quota errors */
    }
  }, []);

  // ---------- Drag (move) — starts from anywhere on the popup except interactive children ----------
  const dragState = useRef<{
    startX: number; startY: number;
    originX: number; originY: number;
  } | null>(null);

  const handleDragPointerDown = (e: React.PointerEvent<HTMLElement>) => {
    console.log('[DRAG] pointerdown', e.clientX, e.clientY, 'button', e.button);
    const button = e.button ?? 0;
    if (button !== 0) return;
    const target = e.target as HTMLElement;
    const blocked = target.closest('button, [role="tab"], input, textarea, select, [data-no-drag], [contenteditable="true"]');
    if (blocked) {
      console.log('[DRAG] blocked by', blocked);
      return;
    }
    const targetEl = e.currentTarget;
    try { targetEl.setPointerCapture?.(e.pointerId); } catch { /* ignore */ }
    const rect = targetEl.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;
    dragState.current = {
      startX: e.clientX,
      startY: e.clientY,
      originX: geomRef.current.x - offsetX,
      originY: geomRef.current.y - offsetY,
    };
    console.log('[DRAG] state set, attaching listeners', dragState.current);
    // Attach move/up handlers inline (same pattern as resize)
    const onMove = (ev: PointerEvent) => {
      console.log('[DRAG] move', ev.clientX, ev.clientY);
      handleDragPointerMove(ev);
    };
    const onUp = () => {
      console.log('[DRAG] up');
      handleDragPointerUp();
      document.removeEventListener('pointermove', onMove);
      document.removeEventListener('pointerup', onUp);
    };
    document.addEventListener('pointermove', onMove);
    document.addEventListener('pointerup', onUp);
  };

  const handleDragPointerMove = (e: PointerEvent) => {
    const d = dragState.current;
    if (!d) return;
    setGeom((prev) => clampState({
      ...prev,
      x: d.originX + e.clientX,
      y: d.originY + e.clientY,
    }));
  };

  const handleDragPointerUp = () => {
    if (!dragState.current) return;
    dragState.current = null;
    persistGeom();
  };

  // ---------- Resize — image-editor style: 8 handles (4 corners + 4 edges) ----------
  // Each corner resizes both axes; each edge resizes one axis with the
  // opposite edge anchored (e.g. dragging E only changes width; W changes
  // both x and width).
  type ResizeEdge = 'n' | 's' | 'e' | 'w' | 'ne' | 'nw' | 'se' | 'sw';
  const resizeState = useRef<{
    edge: ResizeEdge;
    startX: number; startY: number;
    originX: number; originY: number;
    originW: number; originH: number;
  } | null>(null);

  const handleResizePointerDown = (edge: ResizeEdge) => (e: React.PointerEvent<HTMLDivElement>) => {
    console.log('[RESIZE] pointerdown edge', edge, e.clientX, e.clientY);
    const button = e.button ?? 0;
    if (button !== 0) return;
    e.stopPropagation();
    try { e.currentTarget.setPointerCapture?.(e.pointerId); } catch { /* ignore */ }
    const g = geomRef.current;
    resizeState.current = {
      edge,
      startX: e.clientX,
      startY: e.clientY,
      originX: g.x,
      originY: g.y,
      originW: g.width,
      originH: g.height,
    };
    console.log('[RESIZE] state set, attaching listeners', resizeState.current);
    const onMove = (ev: PointerEvent) => {
      console.log('[RESIZE] move edge', edge, ev.clientX, ev.clientY);
      handleResizePointerMove(ev);
    };
    const onUp = () => {
      console.log('[RESIZE] up edge', edge);
      handleResizePointerUp();
      document.removeEventListener('pointermove', onMove);
      document.removeEventListener('pointerup', onUp);
    };
    document.addEventListener('pointermove', onMove);
    document.addEventListener('pointerup', onUp);
  };

  const handleResizePointerMove = (e: PointerEvent) => {
    const r = resizeState.current;
    if (!r) return;
    const dx = e.clientX - r.startX;
    const dy = e.clientY - r.startY;
    setGeom((prev) => {
      let { x: nx, y: ny, width: nw, height: nh } = prev;
      switch (r.edge) {
        case 'e':
          nw = Math.max(MIN_WIDTH,  nw + dx); break;
        case 'w':  // west edge — drag any grows width (anchor: east); x follows drag
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          break;
        case 's':  // south edge — drag down grows height (anchor: north)
          nh = Math.max(MIN_HEIGHT, nh + dy); break;
        case 'n':  // north edge — drag any grows height (anchor: south); y follows drag
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + Math.abs(dy));
          break;
        case 'ne': // top-right corner — drag down-right grows both (anchor: SW)
          nw = Math.max(MIN_WIDTH,  nw + dx);
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
        case 'nw': // top-left corner — drag any grows both (anchor: SE); x, y follow
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + Math.abs(dy));
          break;
        case 'se': // bottom-right corner — drag any grows both (anchor: NW)
          nw = Math.max(MIN_WIDTH,  nw + dx);
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
        case 'sw': // bottom-left corner — drag any grows both (anchor: NE); x follows drag
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
      }
      return clampState({ x: nx, y: ny, width: nw, height: nh });
    });
  };

  const handleResizePointerUp = () => {
    if (!resizeState.current) return;
    resizeState.current = null;
    persistGeom();
  };

  // Attach window-level move/up listeners while drag or resize is active
  // Persist beforeunload (best-effort)
  useEffect(() => {
    const handler = () => persistGeom();
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [persistGeom]);

  // Clamp on viewport resize
  useEffect(() => {
    const onResize = () => setGeom((prev) => clampState(prev));
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const handleOpen = () => {
    setOpen((v) => !v);
    if (!open) setUnseen(0); // opening the popup resets unseen
  };

  const handleClose = () => {
    persistGeom();
    setOpen(false);
  };

  return (
    <>
      <button
        type="button"
        onClick={handleOpen}
        aria-label="Toggle Brain activity"
        aria-expanded={open}
        data-testid="titlebar-brain-button"
        data-brain-toggle
        className={cn(
          'relative p-1 hover:bg-accent rounded text-muted-foreground hover:text-foreground transition',
          open && 'bg-accent text-foreground',
        )}
        title="Brain activity"
      >
        <Brain className="size-4" />
        {unseen > 0 && (
          <span
            data-testid="brain-pulse-dot"
            className="absolute top-0.5 right-0.5 size-2 rounded-full bg-primary ring-2 ring-background animate-pulse"
            aria-label={`${unseen} unseen brain event(s)`}
          />
        )}
      </button>

      {open && createPortal(<PopupContents
        geom={geom}
        tab={tab}
        setTab={setTab}
        handleClose={handleClose}
        handleDragPointerDown={handleDragPointerDown}
        handleResizePointerDown={handleResizePointerDown}
      />, document.body)}
    </>
  );
}

/* ── PopupContents — rendered via createPortal(document.body) so
 * position: fixed escapes any transformed ancestor (e.g. framer-motion
 * <motion.div> in ChatLayout). */
function PopupContents({
  geom,
  tab,
  setTab,
  handleClose,
  handleDragPointerDown,
  handleResizePointerDown,
}: {
  geom: PopupState;
  tab: TabKey;
  setTab: (k: TabKey) => void;
  handleClose: () => void;
  handleDragPointerDown: (e: React.PointerEvent<HTMLElement>) => void;
  handleResizePointerDown: (edge: 'n' | 's' | 'e' | 'w' | 'ne' | 'nw' | 'se' | 'sw') =>
    (e: React.PointerEvent<HTMLDivElement>) => void;
}) {
  const handleStyle = 'absolute z-10 group hover:bg-primary/20 focus-visible:bg-primary/25 transition';
  const handleFillStyle = 'absolute inset-0';
  const cornerHandles = (
    <>
      {/* NW */}
      <div
        data-testid="brain-resize-nw"
        data-brain-resize-edge="nw"
        data-no-drag
        onPointerDown={handleResizePointerDown('nw')}
        className={cn(handleStyle, 'top-0 left-0 size-3 cursor-nw-resize')}
        aria-label="Resize north-west"
      >
        <div className={handleFillStyle} />
      </div>
      {/* NE */}
      <div
        data-testid="brain-resize-ne"
        data-brain-resize-edge="ne"
        data-no-drag
        onPointerDown={handleResizePointerDown('ne')}
        className={cn(handleStyle, 'top-0 right-0 size-3 cursor-ne-resize')}
        aria-label="Resize north-east"
      >
        <div className={handleFillStyle} />
      </div>
      {/* SW */}
      <div
        data-testid="brain-resize-sw"
        data-brain-resize-edge="sw"
        data-no-drag
        onPointerDown={handleResizePointerDown('sw')}
        className={cn(handleStyle, 'bottom-0 left-0 size-3 cursor-sw-resize')}
        aria-label="Resize south-west"
      >
        <div className={handleFillStyle} />
      </div>
      {/* SE */}
      <div
        data-testid="brain-resize-se"
        data-brain-resize-edge="se"
        data-no-drag
        onPointerDown={handleResizePointerDown('se')}
        className={cn(handleStyle, 'bottom-0 right-0 size-3 cursor-se-resize')}
        aria-label="Resize south-east"
      >
        <div className={handleFillStyle} />
      </div>
    </>
  );

  const edgeHandles = (
    <>
      {/* N */}
      <div
        data-testid="brain-resize-n"
        data-brain-resize-edge="n"
        data-no-drag
        onPointerDown={handleResizePointerDown('n')}
        className={cn(handleStyle, 'top-0 left-3 right-3 h-1.5 cursor-n-resize')}
        aria-label="Resize north"
      />
      {/* S */}
      <div
        data-testid="brain-resize-s"
        data-brain-resize-edge="s"
        data-no-drag
        onPointerDown={handleResizePointerDown('s')}
        className={cn(handleStyle, 'bottom-0 left-3 right-3 h-1.5 cursor-s-resize')}
        aria-label="Resize south"
      />
      {/* E */}
      <div
        data-testid="brain-resize-e"
        data-brain-resize-edge="e"
        data-no-drag
        onPointerDown={handleResizePointerDown('e')}
        className={cn(handleStyle, 'top-3 bottom-3 right-0 w-1.5 cursor-e-resize')}
        aria-label="Resize east"
      />
      {/* W */}
      <div
        data-testid="brain-resize-w"
        data-brain-resize-edge="w"
        data-no-drag
        onPointerDown={handleResizePointerDown('w')}
        className={cn(handleStyle, 'top-3 bottom-3 left-0 w-1.5 cursor-w-resize')}
        aria-label="Resize west"
      />
    </>
  );

  return (
    <div
      data-testid="brain-popup"
      data-brain-popup-root
      role="dialog"
      aria-label="Brain activity"
      onPointerDown={handleDragPointerDown}
      className="fixed bg-popover border border-border rounded-xl shadow-2xl flex flex-col overflow-hidden cursor-grab touch-none select-none"
      style={{ left: geom.x, top: geom.y, width: geom.width, height: geom.height }}
    >
      {/* Header (still has the brain-drag-handle testid for backwards compat) */}
      <div
        data-testid="brain-drag-handle"
        className="flex items-center justify-between px-3 py-2 border-b border-border shrink-0"
      >
        <div className="flex items-center gap-2 pointer-events-none">
          <Brain className="size-4 text-primary" />
          <span className="text-sm font-semibold">Brain</span>
          <span className="text-[10px] text-muted-foreground/70 uppercase tracking-wider">
            realtime flow
          </span>
        </div>
        <button
          type="button"
          onClick={handleClose}
          aria-label="Close"
          className="p-1 rounded hover:bg-muted text-muted-foreground hover:text-foreground pointer-events-auto"
        >
          <X className="size-4" />
        </button>
      </div>

      {/* Tabs (data-no-drag is read by the closest() check inside handleDragPointerDown) */}
      <div
        data-no-drag
        className="flex items-center gap-1 px-2 pt-1.5 border-b border-border shrink-0"
      >
        {(
          [
            { key: 'activity' as const, label: 'Activity', icon: Activity },
            { key: 'learning' as const, label: 'Learning', icon: Sparkles },
            { key: 'health'   as const, label: 'Health',   icon: Heart },
          ]
        ).map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            type="button"
            onClick={() => setTab(key)}
            className={cn(
              'flex items-center gap-1 px-2.5 py-1 text-[11px] rounded-t-md border-b-2 transition',
              tab === key
                ? 'border-primary text-foreground bg-popover'
                : 'border-transparent text-muted-foreground hover:text-foreground hover:bg-muted/50',
            )}
            data-testid={`brain-popup-tab-${key}`}
          >
            <Icon className="size-3" />
            {label}
          </button>
        ))}
      </div>

      {/* Body */}
      <div className="flex-1 overflow-y-auto p-2">
        {tab === 'activity' && <BrainActivityTab />}
        {tab === 'learning' && <LearningTab />}
        {tab === 'health' && <SystemHealthTab />}
      </div>

      {/* Resize handles (image-editor style) */}
      {cornerHandles}
      {edgeHandles}

      {/* Backwards-compatible single resize handle (kept for v4.4.2 tests).
          Re-exported to point at the SE corner so old assertions still match. */}
      <div
        data-testid="brain-resize-handle"
        data-no-drag
        onPointerDown={handleResizePointerDown('se')}
        className="absolute bottom-0 right-0 size-3 cursor-se-resize z-10"
        aria-label="Resize brain popup"
        aria-valuenow={geom.width}
        aria-valuemin={MIN_WIDTH}
        aria-valuemax={1200}
        style={{ pointerEvents: 'auto' }}
      />
    </div>
  );
}

/* ── Chat-first layout ────────────────────────────────────────────── */
/*                                                                          */
/* The right-side Workbench sidebar is rendered as a layout sidebar with    */
/* Preview, Diff, Terminal, Tasks, and Plan sections.                       */

import { useState, useEffect, useRef } from "react";
import { Outlet, useLocation, useNavigate, useParams } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { useStore } from "@nanostores/react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { $sessions, createSession } from "@/store/sessions";
import { $currentWorkspaceId, $workspaces } from "@/store/workspaces";
import { ChatTitlebar } from "./ChatTitlebar";
import { SessionSidebar } from "./SessionSidebar";
import { RightDrawer } from "./RightDrawer";
import { addRightDrawerSection, closeRightDrawer, setActiveRightDrawerSection, useRightDrawer } from "./RightDrawerState";
import { approveWorkbenchPlan, getWorkbenchSession, rejectWorkbenchPlan, setWorkbenchGuardMode, streamWorkbenchRevision } from "@/api/workbench";
import { toast } from "sonner";
import type { WorkbenchSession } from "@/types/workbench";
import type { RightDrawerSectionId } from "./RightDrawerState";
import { dispatchFocusComposer, dispatchInsertComposerText, onUiAction } from "@/api/ui-events";

const SESSIONS_COLLAPSED_KEY = "august-sessions-collapsed";
const WORKBENCH_SIDEBAR_OPEN_KEY = "august-workbench-sidebar-open";

export function ChatLayout() {
  const navigate = useNavigate();
  const location = useLocation();
  const { sessionId } = useParams<{ sessionId?: string }>();
  const [collapsed, setCollapsed] = useState<boolean>(
    () => localStorage.getItem(SESSIONS_COLLAPSED_KEY) === "1",
  );
  const [showRightSidebar, setShowRightSidebar] = useState<boolean>(
    () => localStorage.getItem(WORKBENCH_SIDEBAR_OPEN_KEY) === "1",
  );
  const sessions = useStore($sessions);
  const rightDrawer = useRightDrawer();
  const queryClient = useQueryClient();
  const currentWorkspaceId = useStore($currentWorkspaceId);
  const workspaces = useStore($workspaces);
  const active =
    sessions.find((s) => s.id === sessionId && !s.isArchived) ?? null;

  // Get current workspace path for auto-assigning to new sessions
  const currentWorkspacePath = currentWorkspaceId
    ? workspaces.find(w => w.id === currentWorkspaceId)?.path ?? null
    : null;

  useEffect(() => {
    localStorage.setItem(
      WORKBENCH_SIDEBAR_OPEN_KEY,
      showRightSidebar ? "1" : "0",
    );
  }, [showRightSidebar]);

  useEffect(() => {
    if (rightDrawer.open && !showRightSidebar) {
      setShowRightSidebar(true);
    }
  }, [rightDrawer.open, showRightSidebar]);

  const openWorkbenchSidebar = (section: RightDrawerSectionId) => {
    addRightDrawerSection(section);
    setShowRightSidebar(true);
  };

  useEffect(() => {
    localStorage.removeItem("august-show-right-sidebar");
  }, []);

  // Listen for the "open right sidebar" event dispatched by the PlanProposalBanner
  // (and any other in-chat call-to-action) so the drawer opens without the
  // caller needing access to the layout's setter.
  useEffect(() => {
    const handler = () => setShowRightSidebar(true);
    window.addEventListener('august:open-right-sidebar', handler);
    return () => window.removeEventListener('august:open-right-sidebar', handler);
  }, []);

  // Task 5: listen for august:ui-action events from the LLM/tool layer.
  // API/state actions only — no DOM clicks/fills (locked decision 3).
  const workbenchSessionId = active?.workbenchSessionId;
  useEffect(() => {
    const handler = (e: { action: string; target: string; payload?: Record<string, unknown> }) => {
      switch (e.action) {
        case 'navigate':
          void navigate(e.target);
          break;
        case 'open_drawer': {
          const section = (e.payload?.section || 'preview') as RightDrawerSectionId;
          addRightDrawerSection(section);
          setShowRightSidebar(true);
          break;
        }
        case 'close_drawer':
          closeRightDrawer();
          setShowRightSidebar(false);
          break;
        case 'set_drawer_section': {
          const section = e.target as RightDrawerSectionId;
          if (['preview', 'diff', 'terminal', 'tasks', 'plan'].includes(section)) {
            addRightDrawerSection(section);
            setActiveRightDrawerSection(section);
            setShowRightSidebar(true);
          }
          break;
        }
        case 'set_guard_mode':
          if (workbenchSessionId) {
            const mode = e.target as 'plan' | 'ask' | 'full';
            setWorkbenchGuardMode(workbenchSessionId, mode)
              .catch(err => toast.error(`Failed to update guard mode: ${err?.message || err}`));
          }
          break;
        case 'refresh':
          void queryClient.invalidateQueries();
          break;
        case 'focus_composer':
          dispatchFocusComposer();
          break;
        case 'insert_composer_text':
          dispatchInsertComposerText(e.target || '');
          break;
      }
    };
    const unsubscribe = onUiAction(handler);
    return unsubscribe;
  }, [navigate, queryClient, workbenchSessionId]);

  // Fetch the active workbench session to feed the right sidebar. The chat
  // thread also fetches this independently, so this is the layout-level mirror.
  const workbench = useQuery({
    queryKey: ['workbench-session', active?.workbenchSessionId],
    queryFn: () =>
      active?.workbenchSessionId
        ? getWorkbenchSession(active.workbenchSessionId)
        : Promise.resolve(null),
    enabled: !!active?.workbenchSessionId,
    refetchInterval: 2_000,
  });
  const workbenchSession: WorkbenchSession | null = workbench.data || null;

  // Auto-open the Tasks section when todos first appear.
  const hasTodosRef = useRef(false);
  useEffect(() => {
    const hasTodos = (workbenchSession?.todos?.length ?? 0) > 0;
    if (hasTodos && !hasTodosRef.current) {
      hasTodosRef.current = true;
      addRightDrawerSection('tasks');
      setShowRightSidebar(true);
    } else if (!hasTodos) {
      hasTodosRef.current = false;
    }
  }, [workbenchSession?.todos?.length]);

  // Auto redirect from `/` or invalid/archived sessionId to the first non-archived session
  useEffect(() => {
    const activeSessions = sessions.filter((s) => !s.isArchived);
    if (location.pathname === "/" || location.pathname === "") {
      let activeSess = activeSessions[0];
      if (!activeSess) {
        activeSess = createSession(null, 'New Chat', currentWorkspacePath);
      }
      void navigate(`/c/${activeSess.id}`, { replace: true });
    } else if (location.pathname.startsWith("/c/")) {
      const match = sessions.find((s) => s.id === sessionId);
      if (!match || match.isArchived) {
        const fallback = activeSessions[0] || createSession(null, 'New Chat', currentWorkspacePath);
        void navigate(`/c/${fallback.id}`, { replace: true });
      }
    }
  }, [location.pathname, sessionId, sessions, navigate, currentWorkspacePath]);

  const handleNewSession = (folderId?: string | null) => {
    const newSess = createSession(folderId ?? null, 'New Chat', currentWorkspacePath);
    void navigate(`/c/${newSess.id}`);
  };

  const approvePlan = async () => {
    if (!active?.workbenchSessionId) return;
    try {
      const updated = await approveWorkbenchPlan(active.workbenchSessionId);
      queryClient.setQueryData(['workbench-session', active.workbenchSessionId], updated);
      toast.success('Workbench plan approved');
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not approve Workbench plan', { description: message });
    }
  };

  const rejectPlan = async () => {
    if (!active?.workbenchSessionId) return;
    try {
      const updated = await rejectWorkbenchPlan(active.workbenchSessionId);
      queryClient.setQueryData(['workbench-session', active.workbenchSessionId], updated);
      toast.success('Workbench plan rejected');
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not reject Workbench plan', { description: message });
    }
  };

  const revisePlan = async (feedback: string) => {
    if (!active?.workbenchSessionId) return;
    try {
      await streamWorkbenchRevision(active.workbenchSessionId, feedback, {
        onError: (data) => toast.error('Could not send plan revision', { description: data.message }),
        onSession: () => { void queryClient.invalidateQueries({ queryKey: ['workbench-session', active.workbenchSessionId] }); },
      });
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not send plan revision', { description: message });
    }
  };

  const closeWorkbenchSidebar = () => {
    closeRightDrawer();
    setShowRightSidebar(false);
  };

  useEffect(() => {
    localStorage.setItem(SESSIONS_COLLAPSED_KEY, collapsed ? "1" : "0");
  }, [collapsed]);

  // Settings is a FULL-SCREEN page (not a modal). When the path is
  // /settings/*, render the SettingsPage full-width with the chat
  // thread + right drawer hidden. The session sidebar stays visible.
  const isSettings = location.pathname.startsWith("/settings");

  return (
    <div className="h-screen flex flex-col bg-background text-foreground">
      <div className="flex-1 flex min-h-0">
        {!isSettings && (
          <SessionSidebar
            activeId={active?.id}
            collapsed={collapsed}
            onToggleCollapsed={() => setCollapsed((c) => !c)}
            onNew={() => handleNewSession()}
            onNewInFolder={(folderId) => handleNewSession(folderId)}
            onNavigate={(path) => {
              if (path.startsWith("settings") || path.startsWith("/settings")) {
                sessionStorage.setItem("pre-settings-path", location.pathname);
              }
              void navigate(path.startsWith("/") ? path : `/${path}`);
            }}
          />
        )}

        <div className="flex-1 flex flex-col min-w-0">
          <ChatTitlebar
            session={active}
            sidebarCollapsed={collapsed}
            rightDrawerOpen={showRightSidebar}
            onToggleSidebar={() => setCollapsed((c) => !c)}
            onSettings={() => {
              sessionStorage.setItem("pre-settings-path", location.pathname);
              void navigate("/settings");
            }}
            onSelectRightDrawerSection={openWorkbenchSidebar}
          />
          <div className="flex-1 min-h-0 overflow-hidden relative flex">
            {/* Settings takes the full width (its own internal layout). */}
            {isSettings ? (
              <div className="flex-1 min-w-0 h-full">
                <AnimatePresence mode="wait" initial={false}>
                  <motion.div
                    key={location.pathname}
                    initial={{ opacity: 0, y: 6 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -4 }}
                    transition={{ duration: 0.18, ease: [0.16, 1, 0.3, 1] }}
                    className="h-full min-w-0"
                  >
                    <Outlet />
                  </motion.div>
                </AnimatePresence>
              </div>
            ) : (
              <>
                {/* Full-width chat column — scroll container spans the full
                    chat-area width so the thumb sits at the chat-area edge.
                    Internal content max-width is applied inside ChatThread
                    for message readability. */}
                <div className="flex-1 flex min-w-0 h-full">
                  <AnimatePresence mode="wait" initial={false}>
                    <motion.div
                      key={location.pathname}
                      initial={{ opacity: 0, y: 6 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -4 }}
                      transition={{ duration: 0.18, ease: [0.16, 1, 0.3, 1] }}
                      className="h-full min-w-0 flex-1"
                    >
                      <Outlet />
                    </motion.div>
                  </AnimatePresence>
                </div>

                {!isSettings && active && (
                  <RightDrawer
                    open={showRightSidebar}
                    sessionId={active.id}
                    workspacePath={active.workspacePath || null}
                    workbenchSession={workbenchSession}
                    onApprovePlan={approvePlan}
                    onRejectPlan={rejectPlan}
                    onRevisePlan={revisePlan}
                    onClose={closeWorkbenchSidebar}
                  />
                )}
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import {
  Volume2,
  Minus,
  Square,
  X,
  PanelLeft,
  PanelLeftClose,
  Settings,
  GitBranch,
  Download,
  Minimize2,
} from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { gitApi } from "@/api/git";
import { cn } from "@/lib/utils";
import { isTauri } from "@/lib/tauri-detect";
import { toast } from "sonner";
import { RightDrawerDropdown } from "./RightDrawerLauncher";
import { BrainIndicator } from "./BrainIndicator";
import type { Session } from "@/store/sessions";
import type { RightDrawerSectionId } from "./RightDrawerState";

interface ChatTitlebarProps {
  session: Session | null;
  sidebarCollapsed: boolean;
  rightDrawerOpen: boolean;
  onToggleSidebar: () => void;
  onSelectRightDrawerSection: (section: RightDrawerSectionId) => void;
  onSettings: () => void;
}

export function ChatTitlebar({
  session,
  sidebarCollapsed,
  rightDrawerOpen,
  onToggleSidebar,
  onSelectRightDrawerSection,
  onSettings,
}: ChatTitlebarProps) {
  const [speaking, setSpeaking] = useState(false);
  const [isMaximized, setIsMaximized] = useState(false);
  const [updateAvailable, setUpdateAvailable] = useState<{
    version: string;
  } | null>(null);
  const [updating, setUpdating] = useState(false);

  const branch = useQuery({
    queryKey: ['git', 'branch', session?.id],
    queryFn: () => gitApi.branch(session?.id),
    refetchInterval: 30_000,
    retry: false,
  });
  const currentBranch = branch.data?.current;

  // ── Window controls (Tauri only) ──
  useEffect(() => {
    if (!isTauri) return;
    void (async () => {
      try {
        const { getCurrentWindow } = await import("@tauri-apps/api/window");
        const win = getCurrentWindow();
        setIsMaximized(await win.isMaximized());
      } catch { /* silent */ }
    })();
  }, /* eslint-disable-line react-hooks/exhaustive-deps */ []);

  const handleMinimize = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      await getCurrentWindow().minimize();
    } catch { /* silent */ }
  };

  const handleToggleMaximize = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      const win = getCurrentWindow();
      await win.toggleMaximize();
      setIsMaximized(await win.isMaximized());
    } catch { /* silent */ }
  };

  const handleClose = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      await getCurrentWindow().close();
    } catch { /* silent */ }
  };

  // ── Auto-update check (Tauri only) ──
  useEffect(() => {
    if (!isTauri) return;
    void (async () => {
      try {
        const { check } = await import("@tauri-apps/plugin-updater");
        const update = await check();
        if (update) {
          setUpdateAvailable({ version: update.version });
        }
      } catch {
        // Silently ignore — update check is best-effort
      }
    })();
  }, /* eslint-disable-line react-hooks/exhaustive-deps */ []);

  const handleInstallUpdate = async () => {
    if (!isTauri || !updateAvailable) return;
    setUpdating(true);
    try {
      const { check } = await import("@tauri-apps/plugin-updater");
      const update = await check();
      if (update) {
        await update.downloadAndInstall();
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      toast.error(message || "Failed to install update");
      setUpdating(false);
    }
  };

  const speakLatest = () => {
    if (speaking) {
      window.speechSynthesis.cancel();
      setSpeaking(false);
      return;
    }
    const lastMessage = sessionStorage.getItem("august_last_assistant_message");
    if (!lastMessage) {
      toast.info("No message to read");
      return;
    }
    const utterance = new SpeechSynthesisUtterance(lastMessage);
    utterance.rate = 1;
    utterance.pitch = 1;
    utterance.onend = () => setSpeaking(false);
    utterance.onerror = () => setSpeaking(false);
    window.speechSynthesis.speak(utterance);
    setSpeaking(true);
  };

  return (
    <header data-tauri-drag-region className="h-12 bg-background flex items-center justify-between shrink-0 select-none">
      <div className="flex items-center min-w-0">
        <button
          onClick={onToggleSidebar}
          className="size-12 flex items-center justify-center shrink-0 hover:bg-accent text-muted-foreground hover:text-foreground transition"
          title={sidebarCollapsed ? "Show sidebar" : "Hide sidebar"}
        >
          {sidebarCollapsed ? (
            <PanelLeftClose className="size-4" />
          ) : (
            <PanelLeft className="size-4" />
          )}
        </button>

        {/* Update notification button */}
        {updateAvailable && (
          <button
            onClick={() => { void handleInstallUpdate(); }}
            disabled={updating}
            className="flex items-center gap-1.5 px-2.5 py-1 mx-1 text-xs font-medium 
              bg-amber-500/15 text-amber-400 hover:bg-amber-500/25 
              rounded-md transition disabled:opacity-50"
            title={`Update to v${updateAvailable.version}`}
          >
            <Download className="size-3" />
            {updating ? "Updating…" : `v${updateAvailable.version} available`}
          </button>
        )}

        <div className="flex items-center gap-2 px-2 min-w-0">
          <h1 className="text-[13px] font-medium text-foreground truncate">
            {session?.title ?? "General Assistance Conversation Started"}
          </h1>
          {currentBranch && (
            <span
              className="inline-flex items-center gap-1 text-[10px] font-mono text-muted-foreground/80 bg-white/[0.04] border border-white/[0.06] px-1.5 py-0.5 rounded-md"
              title={`Current git branch`}
            >
              <GitBranch size={10} />
              {currentBranch}
            </span>
          )}
          <button
            onClick={onSettings}
            className="p-1 hover:bg-accent rounded text-muted-foreground hover:text-foreground transition"
            title="Open settings"
          >
            <Settings className="size-4" />
          </button>
          {/* v4.4.1 — BrainIndicator (self-contained: icon + pulse dot + floating popup) */}
          <BrainIndicator />
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button
          onClick={speakLatest}
          className={cn(
            "p-1 hover:bg-accent rounded transition",
            speaking
              ? "text-primary animate-pulse"
              : "text-muted-foreground hover:text-foreground",
          )}
          title={speaking ? "Stop reading" : "Read latest response"}
        >
          <Volume2 className="size-4" />
        </button>
        <RightDrawerDropdown drawerOpen={rightDrawerOpen} onSelect={onSelectRightDrawerSection} />

        <div className="h-4 w-[1px] bg-border/40" />

        {/* Windows-style title bar buttons */}
        <div className="flex items-stretch ml-1">
          <button
            onClick={() => { void handleMinimize(); }}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-white/10 transition-colors"
            aria-label="Minimize"
          >
            <Minus className="size-4" />
          </button>
          <button
            onClick={() => { void handleToggleMaximize(); }}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-white/10 transition-colors"
            aria-label={isMaximized ? "Restore" : "Maximize"}
          >
            {isMaximized ? <Minimize2 className="size-3.5" /> : <Square className="size-3" />}
          </button>
          <button
            onClick={() => { void handleClose(); }}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-red-500 hover:text-white transition-colors"
            aria-label="Close"
          >
            <X className="size-4" />
          </button>
        </div>
      </div>
    </header>
  );
}

/* ── Session list — the actual sidebar from the screenshot ─────────── */
/* Top:   New session (⌘N) + Skills & Tools + Artifacts                      */
/* Middle: search, PINNED, SESSIONS (count)                                */
/* Bottom: ⌂ + ⚙ ⏵ ⟳ + status                                  */

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence, LayoutGroup } from "framer-motion";
import {
  Plus,
  Search,
  Pin,
  MessageSquare,
  Wrench,
  Package,
  MoreHorizontal,
  Settings,
  Folder as FolderIcon,
  FolderOpen,
  FolderPlus,
  ChevronRight,
  Edit3,
  Trash2,
  Archive,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { isTauri } from "@/lib/tauri-detect";
import { fadeUp, hoverScale } from "@/lib/motion";
import { useStore } from "@nanostores/react";
import {
  $sessions,
  $folders,
  $sessionStates,
  clearSessionStatus,
  renameSession,
  deleteSession,
  archiveSession,
  moveSessionToFolder,
  createFolder,
  renameFolder,
  deleteFolder,
  toggleFolderCollapse,
  findOrCreateSessionForPath,
  type Session,
  type Folder,
  type SessionStatus,
} from "@/store/sessions";
import { $currentWorkspaceId, $workspaces } from "@/store/workspaces";
import { $activeChatSessions, startChatActiveStreamsPoller } from "@/store/chat-active-streams";
import { toast } from "sonner";
import { modelDisplayParts } from "@/sections/chat/ChatThread";

const SESSIONS_KEY = "august-pinned-sessions";
const STORAGE = (() => {
  try {
    return JSON.parse(localStorage.getItem(SESSIONS_KEY) || "[]") as string[];
  } catch {
    return [];
  }
})();

interface Props {
  activeId?: string;
  collapsed: boolean;
  onToggleCollapsed: () => void;
  onSelect: (s: Session) => void;
  onNew: () => void;
  onNewInFolder?: (folderId: string) => void;
  onNavigate: (path: string) => void;
}

export function SessionList({
  activeId,
  collapsed: _collapsed,
  onToggleCollapsed: _onToggleCollapsed,
  onSelect,
  onNew,
  onNewInFolder,
  onNavigate,
}: Props) {
  const [filter, setFilter] = useState("");
  const [pinnedIds, setPinnedIds] = useState<Set<string>>(new Set(STORAGE));
  const [uncategorizedCollapsed, setUncategorizedCollapsed] = useState(
    () => localStorage.getItem("august-uncategorized-collapsed") === "1",
  );

  const sessions = useStore($sessions);
  const folders = useStore($folders);
  const sessionStates = useStore($sessionStates);
  const activeChatSessions = useStore($activeChatSessions);
  const currentWorkspaceId = useStore($currentWorkspaceId);
  const workspaces = useStore($workspaces);

  useEffect(() => {
    startChatActiveStreamsPoller();
  }, []);

  // Merge the local per-session status with the live poller output so a
  // session that has a backend generation in progress shows the pulse
  // dot even when the user is on a different session. The local status
  // takes precedence when both are present.
  const mergedSessionStates: Record<string, SessionStatus> = (() => {
    const next: Record<string, SessionStatus> = { ...sessionStates };
    for (const [id, status] of Object.entries(activeChatSessions)) {
      if (!next[id]) next[id] = status;
    }
    return next;
  })();

  // Hidden file input for native folder picker (browser fallback)
  const dirInputRef = useRef<HTMLInputElement>(null);

  const handleFolderUploadClick = async (
    e: React.MouseEvent<HTMLButtonElement>,
  ) => {
    e.stopPropagation();

    let selectedPath: string | null = null;

    if (isTauri) {
      try {
        const { invoke } = await import("@tauri-apps/api/core");
        selectedPath = await invoke<string | null>("select_directory");
      } catch (err) {
        console.error("Failed to open Tauri directory dialog:", err);
      }
    } else {
      dirInputRef.current?.click();
      return;
    }

    if (!selectedPath) return;
    selectedPath = selectedPath.trim();
    if (!selectedPath) return;

    // Normalize Windows backslashes
    const normalizedPath = selectedPath.replace(/\\/g, "/");
    const folderName = normalizedPath.split("/").pop() || "workspace";

    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);

    try {
      const res = await fetch(
        `/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`,
      );
      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(
          errData.error || "Directory does not exist or is not readable",
        );
      }

      // Find or auto‑create a session for this folder
      const { session, created } = findOrCreateSessionForPath(normalizedPath, folderName);
      if (created) {
        toast.success(`New session created for folder: ${folderName}`, { id: toastId });
      } else {
        toast.success(`Switched to session for folder: ${folderName}`, { id: toastId });
      }
      onNavigate(`/c/${session.id}`);
      window.dispatchEvent(new CustomEvent("august-open-right-sidebar"));
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      toast.error(`Access failed: ${message}`, { id: toastId });
    }
  };

  const handleDirPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const fullPath = file.path
      || file.webkitRelativePath.slice(0, file.webkitRelativePath.indexOf('/'));
    if (!fullPath) return;
    const normalizedPath = fullPath.replace(/\\/g, "/");
    const folderName = normalizedPath.split("/").pop() || "workspace";
    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);
    void (async () => {
      try {
        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`);
        if (!res.ok) throw new Error((await res.json().catch(() => ({}))).error || 'Directory not accessible');
        // Find or auto‑create a session for this folder
        const { session, created } = findOrCreateSessionForPath(normalizedPath, folderName);
        if (created) {
          toast.success(`New session created for folder: ${folderName}`, { id: toastId });
        } else {
          toast.success(`Switched to session for folder: ${folderName}`, { id: toastId });
        }
        onNavigate(`/c/${session.id}`);
        window.dispatchEvent(new CustomEvent('august-open-right-sidebar'));
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        toast.error(`Access failed: ${message}`, { id: toastId });
      }
    })();
    e.target.value = '';
  };

  const visible = sessions.filter(
    (s) =>
      !s.isArchived &&
      (!filter || s.title.toLowerCase().includes(filter.toLowerCase())),
  );

  // Get current workspace path for filtering
  const currentWorkspacePath = currentWorkspaceId
    ? workspaces.find(w => w.id === currentWorkspaceId)?.path ?? null
    : null;

  // Filter sessions by workspace if one is selected
  const workspaceFiltered = currentWorkspacePath
    ? visible.filter((s) => !s.workspacePath || s.workspacePath === currentWorkspacePath)
    : visible;
  const pinned = workspaceFiltered.filter((s) => pinnedIds.has(s.id));
  const others = workspaceFiltered.filter((s) => !pinnedIds.has(s.id));

  const togglePin = (id: string) => {
    const next = new Set(pinnedIds);
    void (next.has(id) ? next.delete(id) : next.add(id));
    setPinnedIds(next);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify([...next]));
  };

  const handleCreateFolder = () => {
    const name = prompt("Enter folder name:");
    if (name && name.trim()) {
      createFolder(name.trim());
    }
  };

  const handleRenameFolder = (id: string, currentName: string) => {
    const name = prompt("Rename folder:", currentName);
    if (name && name.trim() && name.trim() !== currentName) {
      renameFolder(id, name.trim());
    }
  };

  const handleDeleteFolder = (id: string) => {
    if (
      confirm(
        "Are you sure you want to delete this folder? All sessions inside will be moved to uncategorized.",
      )
    ) {
      deleteFolder(id);
    }
  };

  const toggleUncategorizedCollapse = () => {
    const next = !uncategorizedCollapsed;
    setUncategorizedCollapsed(next);
    localStorage.setItem("august-uncategorized-collapsed", next ? "1" : "0");
  };

  return (
    <div className="flex h-full text-sm relative select-none bg-sidebar">
      <input
        ref={dirInputRef}
        type="file"
        webkitdirectory=""
        directory=""
        className="hidden"
        onChange={handleDirPicked}
      />
      <div className="flex-1 flex flex-col min-w-0 text-sm">
        {/* Nav items */}
        <div className="py-2.5 px-2 flex flex-col gap-0.5">
          <button
            onClick={onNew}
            className="w-full flex items-center justify-between rounded-md px-2.5 py-1.5 text-left text-sidebar-foreground/80 hover:bg-white/5 hover:text-foreground transition"
          >
            <span className="flex items-center gap-2">
              <Plus className="size-3.5" /> New session
            </span>
              <kbd className="text-[10px] text-muted-foreground font-mono bg-muted/20 px-1 py-0.5 rounded border border-border/20">
              ctrl N
            </kbd>
          </button>
          <button
            onClick={() => onNavigate("/settings?tab=mcp")}
            className="w-full text-left rounded-md px-2.5 py-1.5 text-sidebar-foreground/80 hover:bg-white/5 hover:text-foreground transition flex items-center gap-2"
          >
            <Wrench className="size-3.5" /> Skills & Tools
          </button>
          <button
            onClick={() => onNavigate("/settings?tab=overview")}
            className="w-full text-left rounded-md px-2.5 py-1.5 text-sidebar-foreground/80 hover:bg-white/5 hover:text-foreground transition flex items-center gap-2"
          >
            <Package className="size-3.5" /> Artifacts
          </button>
        </div>

        {/* Search input */}
        <div className="px-2 py-2">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-3 text-muted-foreground" />
            <input
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              placeholder="Search sessions..."
              className="w-full pl-8 pr-2 py-1 text-xs bg-white/5 rounded-md border border-transparent focus:border-white/10 focus:bg-white/10 outline-none transition text-sidebar-foreground placeholder:text-muted-foreground"
            />
          </div>
        </div>

        {/* Scrollable sessions area */}
        <div className="flex-1 overflow-y-auto px-2 pb-2 space-y-4">
          <Section
            title="PINNED"
            count={pinned.length}
            empty="Shift-click a chat to pin"
          >
            <LayoutGroup id="pinned-sessions">
              <AnimatePresence initial={false}>
                {pinned.map((s) => (
                  <SessionRow
                    key={s.id}
                    session={s}
                    active={activeId === s.id}
                    pinned
                    status={mergedSessionStates[s.id]}
                    folders={folders}
                    onClick={() => onSelect(s)}
                    onTogglePin={() => togglePin(s.id)}
                    onRename={(newTitle) => renameSession(s.id, newTitle)}
                    onArchive={() => {
                      archiveSession(s.id);
                      if (activeId === s.id) {
                        const fallback = sessions.find(
                          (x) => x.id !== s.id && !x.isArchived,
                        );
                        if (fallback) onSelect(fallback);
                      }
                    }}
                    onMoveToFolder={(fId) => moveSessionToFolder(s.id, fId)}
                    onDelete={() => {
                      if (
                        confirm(
                          "Are you sure you want to permanently delete this chat?",
                        )
                      ) {
                        deleteSession(s.id);
                        if (activeId === s.id) {
                          const fallback = sessions.find(
                            (x) => x.id !== s.id && !x.isArchived,
                          );
                          if (fallback) onSelect(fallback);
                        }
                      }
                    }}
                  />
                ))}
              </AnimatePresence>
            </LayoutGroup>
          </Section>

          <Section
            title="SESSIONS"
            count={others.length}
            onNewFolder={handleCreateFolder}
            onUploadFolder={(e) => { void handleFolderUploadClick(e); }}
          >
            <div className="space-y-2.5">
              {/* Collapsible Folders */}
              {folders.map((folder) => {
                const folderSessions = others.filter(
                  (s) => s.folderId === folder.id,
                );
                const isCollapsed = folder.isCollapsed ?? false;

                return (
                  <div key={folder.id} className="space-y-0.5">
                    <FolderHeader
                      folder={folder}
                      count={folderSessions.length}
                      hasActiveSession={folderSessions.some(
                        (s) => mergedSessionStates[s.id] === "working" || mergedSessionStates[s.id] === "streaming",
                      )}
                      onToggleCollapse={() => toggleFolderCollapse(folder.id)}
                      onNewSession={() => onNewInFolder?.(folder.id)}
                      onRename={() =>
                        handleRenameFolder(folder.id, folder.name)
                      }
                      onDelete={() => handleDeleteFolder(folder.id)}
                    />

                    {!isCollapsed && (
                      <div className="pl-2.5 ml-3.5 space-y-0.5">
                        {folderSessions.map((s) => (
                          <SessionRow
                            key={s.id}
                            session={s}
                            active={activeId === s.id}
                            pinned={false}
                            status={mergedSessionStates[s.id]}
                            folders={folders}
                            onClick={() => onSelect(s)}
                            onTogglePin={() => togglePin(s.id)}
                            onRename={(newTitle) =>
                              renameSession(s.id, newTitle)
                            }
                            onArchive={() => {
                              archiveSession(s.id);
                              if (activeId === s.id) {
                                const fallback = sessions.find(
                                  (x) => x.id !== s.id && !x.isArchived,
                                );
                                if (fallback) onSelect(fallback);
                              }
                            }}
                            onMoveToFolder={(fId) =>
                              moveSessionToFolder(s.id, fId)
                            }
                            onDelete={() => {
                              if (
                                confirm(
                                  "Are you sure you want to permanently delete this chat?",
                                )
                              ) {
                                deleteSession(s.id);
                                if (activeId === s.id) {
                                  const fallback = sessions.find(
                                    (x) => x.id !== s.id && !x.isArchived,
                                  );
                                  if (fallback) onSelect(fallback);
                                }
                              }
                            }}
                          />
                        ))}
                        {folderSessions.length === 0 && (
                          <p className="py-1 text-xs text-muted-foreground/30 italic pl-1.5">
                            Empty folder
                          </p>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}

              {/* Uncategorized Sessions (Other Chats) */}
              {(() => {
                const uncategorizedSessions = others.filter((s) => !s.folderId);

                return (
                  <div className="space-y-0.5">
                    <UncategorizedHeader
                      count={uncategorizedSessions.length}
                      isCollapsed={uncategorizedCollapsed}
                      onToggleCollapse={toggleUncategorizedCollapse}
                    />

                    {!uncategorizedCollapsed && (
                      <div className="pl-2.5 ml-3.5 space-y-0.5">
                        {uncategorizedSessions.map((s) => (
                          <SessionRow
                            key={s.id}
                            session={s}
                            active={activeId === s.id}
                            pinned={false}
                            status={mergedSessionStates[s.id]}
                            folders={folders}
                            onClick={() => onSelect(s)}
                            onTogglePin={() => togglePin(s.id)}
                            onRename={(newTitle) =>
                              renameSession(s.id, newTitle)
                            }
                            onArchive={() => {
                              archiveSession(s.id);
                              if (activeId === s.id) {
                                const fallback = sessions.find(
                                  (x) => x.id !== s.id && !x.isArchived,
                                );
                                if (fallback) onSelect(fallback);
                              }
                            }}
                            onMoveToFolder={(fId) =>
                              moveSessionToFolder(s.id, fId)
                            }
                            onDelete={() => {
                              if (
                                confirm(
                                  "Are you sure you want to permanently delete this chat?",
                                )
                              ) {
                                deleteSession(s.id);
                                if (activeId === s.id) {
                                  const fallback = sessions.find(
                                    (x) => x.id !== s.id && !x.isArchived,
                                  );
                                  if (fallback) onSelect(fallback);
                                }
                              }
                            }}
                          />
                        ))}
                        {uncategorizedSessions.length === 0 && (
                          <p className="py-1 text-xs text-muted-foreground/30 italic pl-1.5">
                            No other chats
                          </p>
                        )}
                      </div>
                    )}
                  </div>
                );
              })()}
            </div>
          </Section>
        </div>

        {/* Settings at bottom */}
        <div className="px-2 pb-2 pt-1 border-t border-border/20">
          <button
            onClick={() => onNavigate("/settings")}
            className="w-full flex items-center gap-2 rounded-md px-2.5 py-1.5 text-left text-sidebar-foreground/80 hover:bg-white/5 hover:text-foreground transition"
          >
            <Settings className="size-3.5" />
            <span>Settings</span>
          </button>
        </div>
      </div>
    </div>
  );
}

function Section({
  title,
  count,
  empty,
  onNewFolder,
  onUploadFolder,
  children,
}: {
  title: string;
  count: number;
  empty?: string;
  onNewFolder?: () => void;
  onUploadFolder?: (e: React.MouseEvent<HTMLButtonElement>) => void;
  children?: React.ReactNode;
}) {
  return (
    <div>
      <div className="flex items-center justify-between mb-1.5 px-2">
        <div className="flex items-center gap-1.5">
            <h3 className="text-[11px] uppercase tracking-caps text-muted-foreground/75 font-semibold">
              {title}
            </h3>
            <span className="text-xs text-muted-foreground/50 font-mono">
              ({count})
            </span>
        </div>
        {title === "SESSIONS" && onNewFolder && onUploadFolder && (
          <div className="flex items-center gap-1">
            <button
              onClick={onUploadFolder}
              className="text-muted-foreground/50 hover:text-foreground p-0.5 rounded transition hover:bg-white/5"
              title="Open Workspace Folder"
            >
              <FolderPlus className="size-3" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onNewFolder();
              }}
              className="text-muted-foreground/50 hover:text-foreground p-0.5 rounded transition hover:bg-white/5"
              title="Create Sidebar Folder"
            >
              <Plus className="size-3" />
            </button>
          </div>
        )}
      </div>
      {count === 0 && title === "PINNED" ? (
        <p className="px-2 py-1 text-xs text-muted-foreground/40 italic">
          {empty ?? "No items"}
        </p>
      ) : (
        <div className="space-y-0.5">{children}</div>
      )}
    </div>
  );
}

function FolderHeader({
  folder,
  count,
  hasActiveSession: _hasActiveSession,
  onToggleCollapse,
  onNewSession,
  onRename,
  onDelete,
}: {
  folder: Folder;
  count: number;
  hasActiveSession?: boolean;
  onToggleCollapse: () => void;
  onNewSession: () => void;
  onRename: () => void;
  onDelete: () => void;
}) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="flex items-center justify-between py-1 px-1.5 rounded-md hover:bg-white/5 cursor-pointer group text-sidebar-foreground/80 font-medium"
      onClick={onToggleCollapse}
    >
      <div className="flex items-center gap-1.5 min-w-0">
        <span
          className={cn(
            "size-1 rounded-full shrink-0 transition-colors",
            folder.isCollapsed ? "bg-muted-foreground/40" : "bg-primary",
          )}
        />
        {folder.isCollapsed ? (
          <FolderIcon className="size-3.5 text-muted-foreground/70 shrink-0" />
        ) : (
          <FolderOpen className="size-3.5 text-muted-foreground/70 shrink-0" />
        )}
        <span className="truncate text-sm font-semibold text-foreground/85">
          {folder.name}
        </span>
        <span className="text-xs text-muted-foreground/50 font-mono">
          ({count})
        </span>
      </div>
      <div
        className="flex items-center gap-0.5 shrink-0"
        onClick={(e) => e.stopPropagation()}
      >
        {isHovered && (
          <>
            <button
              onClick={onNewSession}
              className="p-0.5 hover:bg-white/10 rounded text-muted-foreground hover:text-foreground"
              title={`New session in ${folder.name}`}
            >
              <Plus className="size-2.5" />
            </button>
            <button
              onClick={onRename}
              className="p-0.5 hover:bg-white/10 rounded text-muted-foreground hover:text-foreground"
              title="Rename Folder"
            >
              <Edit3 className="size-2.5" />
            </button>
            <button
              onClick={onDelete}
              className="p-0.5 hover:bg-white/10 rounded text-destructive hover:text-destructive-foreground"
              title="Delete Folder"
            >
              <Trash2 className="size-2.5" />
            </button>
          </>
        )}
        <span
          className={cn(
            "size-3.5 flex items-center justify-center rounded transition-all duration-150",
            folder.isCollapsed
              ? "rotate-0 text-muted-foreground/60"
              : "rotate-90 text-muted-foreground/60",
            !isHovered && "opacity-60",
          )}
        >
          <ChevronRight className="size-3" />
        </span>
      </div>
    </div>
  );
}

function UncategorizedHeader({
  count,
  isCollapsed,
  onToggleCollapse,
}: {
  count: number;
  isCollapsed: boolean;
  onToggleCollapse: () => void;
}) {
  return (
    <div
      className="flex items-center justify-between py-1 px-1.5 rounded-md hover:bg-white/5 cursor-pointer group text-sidebar-foreground/80 font-medium"
      onClick={onToggleCollapse}
    >
      <div className="flex items-center gap-1.5 min-w-0">
        <span
          className={cn(
            "size-1 rounded-full shrink-0 transition-colors",
            isCollapsed ? "bg-muted-foreground/40" : "bg-primary",
          )}
        />
        <MessageSquare className="size-3.5 text-muted-foreground/70 shrink-0" />
        <span className="truncate text-sm font-semibold text-foreground/85">
          Other Chats
        </span>
        <span className="text-xs text-muted-foreground/50 font-mono">
          ({count})
        </span>
      </div>
      <span
        className={cn(
          "size-3.5 flex items-center justify-center rounded transition-all duration-150 shrink-0",
          isCollapsed
            ? "rotate-0 text-muted-foreground/60"
            : "rotate-90 text-muted-foreground/60",
          "opacity-60 group-hover:opacity-100",
        )}
      >
        <ChevronRight className="size-3" />
      </span>
    </div>
  );
}

function SessionRow({
  session,
  active,
  pinned,
  status,
  folders,
  onClick,
  onTogglePin,
  onRename,
  onArchive,
  onMoveToFolder,
  onDelete,
}: {
  session: Session;
  active: boolean;
  pinned: boolean;
  status?: SessionStatus;
  folders: Folder[];
  onClick: () => void;
  onTogglePin: () => void;
  onRename: (title: string) => void;
  onArchive: () => void;
  onMoveToFolder: (folderId: string | null) => void;
  onDelete: () => void;
}) {
  const [showMenu, setShowMenu] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(session.title);

  useEffect(() => {
    if (!showMenu) return;
    const handleClose = () => setShowMenu(false);
    window.addEventListener("click", handleClose);
    return () => window.removeEventListener("click", handleClose);
  }, [showMenu]);

  const handleSaveRename = () => {
    if (editTitle.trim() && editTitle.trim() !== session.title) {
      onRename(editTitle.trim());
    }
    setIsEditing(false);
  };

  if (isEditing) {
    return (
      <div className="w-full px-2 py-1 flex items-center gap-1.5 bg-white/5 rounded-md">
        <input
          autoFocus
          value={editTitle}
          onChange={(e) => setEditTitle(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") handleSaveRename();
            if (e.key === "Escape") {
              setEditTitle(session.title);
              setIsEditing(false);
            }
          }}
          onBlur={handleSaveRename}
          onClick={(e) => e.stopPropagation()}
          className="bg-muted border border-border/80 px-1.5 py-0.5 rounded text-xs w-full outline-none text-foreground"
        />
      </div>
    );
  }

  return (
    <motion.div
      layout="position"
      variants={fadeUp}
      exit={{
        opacity: 0,
        x: -4,
        transition: { duration: 0.12, ease: [0.16, 1, 0.3, 1] },
      }}
      className={cn(
        "group relative rounded-md",
        active ? "bg-white/5" : "hover:bg-white/5",
      )}
    >
      {active && (
        <motion.span
          layoutId="active-session-pill"
          className="absolute inset-0 rounded-md bg-white/5"
          transition={{ type: "spring", stiffness: 380, damping: 32 }}
          aria-hidden="true"
        />
      )}
      <button
        onClick={() => {
          if (status === "done") clearSessionStatus(session.id);
          onClick();
        }}
        onContextMenu={(e) => {
          e.preventDefault();
          onTogglePin();
        }}
        className="relative w-full text-left px-2 py-1.5 flex flex-col gap-0.5 pr-12 min-w-0"
        title="Right click or use three-dots menu to pin"
      >
        <div className="flex items-center gap-1.5">
          <span
            className={cn(
              "inline-block size-1.5 rounded-full shrink-0 transition-colors",
              status === "working" && "bg-warning",
              status === "streaming" && "bg-warning animate-pulse",
              status === "done" && "bg-success",
              status === "awaiting" && "bg-info",
              status === "error" && "bg-danger",
              (!status || status === "idle") && "bg-muted-foreground/60",
            )}
          />
          {pinned && (
            <Pin className="size-2.5 text-muted-foreground/60 shrink-0" />
          )}
          {session.workspacePath && (
            <FolderIcon className="size-3 text-muted-foreground/50 shrink-0" />
          )}
          <p
            className={cn(
              "truncate flex-1 session-list-title",
              active ? "text-foreground font-semibold" : "text-foreground/75",
            )}
          >
            {session.title}
          </p>
        </div>
        <AnimatePresence>
          {status === "streaming" && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="flex items-center gap-1 ml-3 overflow-hidden"
            >
              <span className="text-xs text-warning/80 font-medium">
                {modelDisplayParts(session.model).name}
              </span>
              <motion.span
                className="text-xs text-warning/60 font-medium"
                animate={{ opacity: [0.4, 1, 0.4] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              >
                running in background
              </motion.span>
            </motion.div>
          )}
          {status === "working" && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="flex items-center gap-1 ml-3 overflow-hidden"
            >
              <span className="text-xs text-warning/80 font-medium">
                {modelDisplayParts(session.model).name}
              </span>
              <span className="text-xs text-warning/50">is</span>
              <span className="flex items-center gap-px">
                {["w", "o", "r", "k", "i", "n", "g"].map((ch, i) => (
                  <motion.span
                    key={i}
                    className="text-xs text-warning/70 font-medium inline-block"
                    animate={{ opacity: [0.3, 1, 0.3], y: [1, -1, 1] }}
                    transition={{
                      duration: 0.8,
                      repeat: Infinity,
                      delay: i * 0.08,
                    }}
                  >
                    {ch}
                  </motion.span>
                ))}
              </span>
            </motion.div>
          )}
          {status === "done" && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="flex items-center gap-1 ml-3 overflow-hidden"
            >
              <span className="text-xs text-success/80 font-medium">
                {modelDisplayParts(session.model).name}
              </span>
              <motion.span
                className="text-xs text-success/60 font-medium"
                animate={{ opacity: [0.4, 1, 0.4] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              >
                done
              </motion.span>
            </motion.div>
          )}
          {status === "error" && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="flex items-center gap-1 ml-3 overflow-hidden"
            >
              <span className="text-xs text-danger/80 font-medium">
                {modelDisplayParts(session.model).name}
              </span>
              <span className="text-xs text-danger/60 font-medium">
                error
              </span>
            </motion.div>
          )}
        </AnimatePresence>
      </button>

      {/* Floating kebab menu triggers */}
      <div
