/* ── useLogStream — WebSocket subscriber for Settings → Backend Monitor */
/* Connects to /ui/logs/stream, backfills from /api/logs/recent, appends
 * live frames, dedupes by event id, and exposes pause/resume/clear.
 * Reconnects with exponential backoff (1s → 30s). Capped at MAX_EVENTS. */

import { useCallback, useEffect, useMemo, useRef } from 'react';
import { atom, onMount } from 'nanostores';
import { useStore } from '@nanostores/react';
import { getRecentLogs, type LogEvent } from '@/api/api-client';
import { whenReady } from '@/api/client';

const MAX_EVENTS = 10_000;
const BACKFILL_LIMIT = 500;

export type StreamStatus = 'connecting' | 'live' | 'disconnected' | 'paused';

interface WSFrame {
    type: 'snapshot' | 'event';
    event?: LogEvent;
    events?: LogEvent[];
}

interface StreamState {
    events: LogEvent[];
    status: StreamStatus;
    lastError: string | null;
    retryInMs: number | null;
}

const streamAtom = atom<StreamState>({
    events: [],
    status: 'connecting',
    lastError: null,
    retryInMs: null,
});

const pausedAtom = atom<boolean>(false);

let _socket: WebSocket | null = null;
let _retryTimer: ReturnType<typeof setTimeout> | null = null;
let _retryDelay = 1000;
let _mountedSubscribers = 0;

function pushEvents(newEvents: LogEvent[]) {
    const prev = streamAtom.get().events;
    const seen = new Set(prev.map((e) => e.id));
    const merged: LogEvent[] = [];
    for (let i = newEvents.length - 1; i >= 0; i--) {
        const e = newEvents[i];
        if (!seen.has(e.id)) {
            seen.add(e.id);
            merged.push(e);
        }
    }
    if (merged.length === 0) return;
    const next = [...merged.reverse(), ...prev].slice(0, MAX_EVENTS);
    streamAtom.set({ ...streamAtom.get(), events: next });
}

function pushEvent(event: LogEvent) {
    const prev = streamAtom.get().events;
    if (prev.some((e) => e.id === event.id)) return;
    streamAtom.set({ ...streamAtom.get(), events: [event, ...prev].slice(0, MAX_EVENTS) });
}

function scheduleRetry() {
    if (_retryTimer) return;
    const delay = _retryDelay;
    streamAtom.set({ ...streamAtom.get(), status: 'disconnected', retryInMs: delay });
    _retryTimer = setTimeout(() => {
        _retryTimer = null;
        _retryDelay = Math.min(_retryDelay * 2, 30_000);
        void connect();
	    }, delay);
	}

	async function connect() {
	    if (_socket && (_socket.readyState === WebSocket.OPEN || _socket.readyState === WebSocket.CONNECTING)) return;
    // Tauri desktop: connect directly to the backend (loopback HTTP → ws).
    // Browser dev: same-origin; Vite proxy handles the WS upgrade.
    let wsUrl: string;
    const baseUrl = await whenReady();
    if (baseUrl) {
        const host = baseUrl.replace(/^https?:\/\//, '');
        wsUrl = `ws://${host}/api/logs/stream`;
    } else {
        const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        wsUrl = `${proto}//${window.location.host}/api/logs/stream`;
    }
    let ws: WebSocket;
    try {
        ws = new WebSocket(wsUrl);
    } catch (err) {
        streamAtom.set({ ...streamAtom.get(), lastError: String(err), status: 'disconnected' });
        scheduleRetry();
        return;
    }
    _socket = ws;
    streamAtom.set({ ...streamAtom.get(), status: 'connecting', lastError: null });

    ws.onopen = async () => {
        _retryDelay = 1000;
        streamAtom.set({ ...streamAtom.get(), status: 'live', retryInMs: null });
        try {
            const backfill = await getRecentLogs(BACKFILL_LIMIT);
            pushEvents(backfill.events || []);
        } catch (_e) {
            // Backfill is best-effort; live stream still works
        }
    };
    ws.onmessage = (msg) => {
        if (pausedAtom.get()) return;
        let frame: WSFrame;
        try { frame = JSON.parse(msg.data); } catch { return; }
        if (frame.type === 'snapshot' && Array.isArray(frame.events)) {
            pushEvents(frame.events);
        } else if (frame.type === 'event' && frame.event) {
            pushEvent(frame.event);
        }
    };
    ws.onerror = () => {
        streamAtom.set({ ...streamAtom.get(), lastError: 'WebSocket error' });
    };
    ws.onclose = () => {
        _socket = null;
        if (_mountedSubscribers > 0) scheduleRetry();
        else streamAtom.set({ ...streamAtom.get(), status: 'disconnected', retryInMs: null });
    };
}

function disconnect() {
    if (_retryTimer) { clearTimeout(_retryTimer); _retryTimer = null; }
    if (_socket) {
        const s = _socket;
        _socket = null;
        try { s.close(); } catch { /* ignore */ }
    }
}

export function useLogStream() {
    const state = useStore(streamAtom);
    const paused = useStore(pausedAtom);
    const isMounted = useRef(false);

    useEffect(() => {
        if (isMounted.current) return;
        isMounted.current = true;
        _mountedSubscribers += 1;
        if (!_socket) void connect();
        return () => {
            _mountedSubscribers -= 1;
            if (_mountedSubscribers <= 0) {
                _mountedSubscribers = 0;
                disconnect();
            }
        };
    }, []);

    const pause = useCallback(() => pausedAtom.set(true), []);
    const resume = useCallback(() => pausedAtom.set(false), []);
    const clear = useCallback(() => {
        streamAtom.set({ ...streamAtom.get(), events: [] });
    }, []);

    const status: StreamStatus = paused ? 'paused' : state.status;

    return useMemo(
        () => ({ events: state.events, status, lastError: state.lastError, retryInMs: state.retryInMs, pause, resume, clear }),
        [state.events, status, state.lastError, state.retryInMs, pause, resume, clear],
    );
}

// Mount-once: ensure the atom is hot so first consumer gets a fast render.
// Not required but useful for tests.
onMount(streamAtom, () => () => { /* nothing to clean on unmount */ });

/* ── Provider availability (React Query) ──────────────────────────── */
/* Replaces the one-shot useEffect in ChatThread so newly-added providers */
/* appear in the model dropdown without remounting the chat. */

import { useQuery } from '@tanstack/react-query';

export interface ProviderAvailability {
  id: string;
  name: string;
  apiMode: string;
  isAvailable: boolean;
}

export interface ProviderAvailabilityResponse {
  activeProvider: string | null;
  providers: ProviderAvailability[];
}

export function useProviderAvailability() {
  const q = useQuery<ProviderAvailabilityResponse>({
    queryKey: ['provider-availability'],
    queryFn: async () => {
      const res = await fetch('/api/config/activeProvider');
      if (!res.ok) throw new Error('Failed to fetch provider availability');
      return res.json();
    },
    refetchInterval: 30_000,
    staleTime: 15_000,
  });
  return {
    providers: q.data?.providers ?? ([] as ProviderAvailability[]),
    activeProvider: q.data?.activeProvider ?? null,
    isLoading: q.isLoading,
    error: q.error,
    refetch: q.refetch,
  };
}

/* ── Universal file reader ─ extract text from any file type ──────── */
/* Provides browser-side content extraction so the AI model can read   */
/* attached files. Supports plain text, PDF, DOCX, XLSX, and images.  */

import mammoth from 'mammoth';
import * as XLSX from 'xlsx';

// ── Limits ──────────────────────────────────────────────────────────────────
const TEXT_MAX_CHARS = 100_000;   // 100 KB of extracted text
const IMAGE_MAX_SIZE = 10 * 1024 * 1024; // 10 MB for images

// ── Types ───────────────────────────────────────────────────────────────────
export type FileReadType = 'text' | 'image' | 'unsupported';

export interface FileReadResult {
  type: FileReadType;
  /** Extracted text content (for text-type files). */
  content?: string;
  /** Base64 data URL (for image files). */
  dataUrl?: string;
  /** MIME type of the original file. */
  mimeType: string;
  /** True if content was truncated to stay within limits. */
  truncated?: boolean;
}

// ── Extension → category mapping ────────────────────────────────────────────
const TEXT_EXTENSIONS = new Set([
  // Plain text / code
  'txt', 'md', 'mdx', 'csv', 'tsv', 'json', 'jsonc', 'json5',
  'js', 'mjs', 'cjs', 'jsx', 'ts', 'tsx', 'vue', 'svelte',
  'py', 'rb', 'go', 'rs', 'java', 'kt', 'swift', 'dart',
  'c', 'h', 'cpp', 'cc', 'cxx', 'hpp', 'cs', 'php', 'scala',
  'sh', 'bash', 'zsh', 'fish', 'ps1', 'bat', 'cmd',
  'lua', 'pl', 'hs', 'clj', 'ex', 'exs',
  'html', 'htm', 'xhtml', 'svg', 'css', 'scss', 'sass', 'less',
  'xml', 'yaml', 'yml', 'toml', 'ini', 'cfg', 'conf',
  'sql', 'graphql', 'proto',
  'dockerfile', 'makefile', 'cmake',
  'gitignore', 'gitattributes', 'editorconfig',
  'env', 'log',
  // Misc text
  'rst', 'adoc', 'tex', 'latex',
]);

const IMAGE_EXTENSIONS = new Set([
  'jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff', 'tif', 'avif', 'ico', 'svg',
]);

const IMAGE_MIMES = new Set([
  'image/jpeg', 'image/png', 'image/gif', 'image/webp',
  'image/bmp', 'image/tiff', 'image/svg+xml', 'image/avif',
]);

function getExtension(filename: string): string {
  const dot = filename.lastIndexOf('.');
  if (dot < 0) return '';
  return filename.slice(dot + 1).toLowerCase();
}

// ── Helpers ─────────────────────────────────────────────────────────────────
function readFileAsText(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error(String(reader.error ?? 'FileReader error')));
    reader.readAsText(file);
  });
}

function readFileAsDataUrl(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error(String(reader.error ?? 'FileReader error')));
    reader.readAsDataURL(file);
  });
}

function readFileAsArrayBuffer(file: File): Promise<ArrayBuffer> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as ArrayBuffer);
    reader.onerror = () => reject(new Error(String(reader.error ?? 'FileReader error')));
    reader.readAsArrayBuffer(file);
  });
}

function truncate(text: string, maxChars: number): { content: string; truncated: boolean } {
  if (text.length <= maxChars) return { content: text, truncated: false };
  return { content: text.slice(0, maxChars) + '\n\n[... truncated — file exceeds 100 KB text limit]', truncated: true };
}

// ── PDF extraction ──────────────────────────────────────────────────────────
async function extractPdfText(file: File): Promise<{ content: string; truncated: boolean }> {
  // Dynamic import so the heavy pdf.js library is only loaded when needed
  const pdfjsLib = await import('pdfjs-dist');

  // Set the worker source to a CDN to avoid bundling issues
  pdfjsLib.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

  const arrayBuffer = await readFileAsArrayBuffer(file);
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const maxPages = Math.min(pdf.numPages, 50);
  const textParts: string[] = [];

  for (let i = 1; i <= maxPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const pageText = content.items.map((item: any) => (item.str || '')).join(' ');
    textParts.push(`--- Page ${i} ---\n${pageText}`);
  }

  const fullText = textParts.join('\n\n');
  return truncate(fullText, TEXT_MAX_CHARS);
}

// ── DOCX extraction ─────────────────────────────────────────────────────────
async function extractDocxText(file: File): Promise<{ content: string; truncated: boolean }> {
  const arrayBuffer = await readFileAsArrayBuffer(file);
  const result = await mammoth.extractRawText({ arrayBuffer });
  return truncate(result.value, TEXT_MAX_CHARS);
}

// ── XLSX extraction ─────────────────────────────────────────────────────────
async function extractSpreadsheetText(file: File): Promise<{ content: string; truncated: boolean }> {
  const arrayBuffer = await readFileAsArrayBuffer(file);
  const workbook = XLSX.read(arrayBuffer, { type: 'array' });
  const parts: string[] = [];

  for (const sheetName of workbook.SheetNames) {
    const sheet = workbook.Sheets[sheetName];
    const csv = XLSX.utils.sheet_to_csv(sheet);
    parts.push(`--- Sheet: ${sheetName} ---\n${csv}`);
  }

  return truncate(parts.join('\n\n'), TEXT_MAX_CHARS);
}

// ── Main API ────────────────────────────────────────────────────────────────
/**
 * Read a file and extract its content in a format the AI model can consume.
 *
 * - **Text files**: returns extracted plain text (code, CSV, JSON, etc.)
 * - **PDF**: extracts text page-by-page (up to 50 pages)
 * - **DOCX**: extracts raw text via mammoth
 * - **XLSX/CSV**: extracts as CSV per sheet
 * - **Images**: returns a base64 data URL for vision analysis
 * - **Other**: returns `{ type: 'unsupported' }`
 */
export async function readFileContent(file: File): Promise<FileReadResult> {
  const ext = getExtension(file.name);
  const mimeType = file.type || '';

  // ── Images ──────────────────────────────────────────────────────────
  if (IMAGE_EXTENSIONS.has(ext) || IMAGE_MIMES.has(mimeType)) {
    if (file.size > IMAGE_MAX_SIZE) {
      return { type: 'image', dataUrl: await readFileAsDataUrl(file), mimeType, truncated: true };
    }
    return { type: 'image', dataUrl: await readFileAsDataUrl(file), mimeType };
  }

  // ── PDF ─────────────────────────────────────────────────────────────
  if (ext === 'pdf' || mimeType === 'application/pdf') {
    try {
      const { content, truncated } = await extractPdfText(file);
      return { type: 'text', content, mimeType, truncated };
    } catch (err) {
      console.warn('[file-reader] PDF extraction failed:', err);
      return { type: 'unsupported', mimeType };
    }
  }

  // ── DOCX ────────────────────────────────────────────────────────────
  if (ext === 'docx' || mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
    try {
      const { content, truncated } = await extractDocxText(file);
      return { type: 'text', content, mimeType, truncated };
    } catch (err) {
      console.warn('[file-reader] DOCX extraction failed:', err);
      return { type: 'unsupported', mimeType };
    }
  }

  // ── XLSX / XLS ─────────────────────────────────────────────────────
  if (ext === 'xlsx' || ext === 'xls' || ext === 'ods' ||
      mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
      mimeType === 'application/vnd.ms-excel') {
    try {
      const { content, truncated } = await extractSpreadsheetText(file);
      return { type: 'text', content, mimeType, truncated };
    } catch (err) {
      console.warn('[file-reader] Spreadsheet extraction failed:', err);
      return { type: 'unsupported', mimeType };
    }
  }

  // ── Plain text / code ───────────────────────────────────────────────
  if (TEXT_EXTENSIONS.has(ext) || mimeType.startsWith('text/')) {
    try {
      const raw = await readFileAsText(file);
      const { content, truncated } = truncate(raw, TEXT_MAX_CHARS);
      return { type: 'text', content, mimeType, truncated };
    } catch (err) {
      console.warn('[file-reader] Text extraction failed:', err);
      return { type: 'unsupported', mimeType };
    }
  }

  // ── Try reading as text as a fallback ───────────────────────────────
  if (file.size < 500 * 1024) {
    try {
      const raw = await readFileAsText(file);
      // Check if it looks like text (no null bytes in the first 512 bytes)
      const sample = raw.slice(0, 512);
      if (!sample.includes('\0')) {
        const { content, truncated } = truncate(raw, TEXT_MAX_CHARS);
        return { type: 'text', content, mimeType, truncated };
      }
    } catch { /* silent */ }
  }

  return { type: 'unsupported', mimeType };
}

/**
 * tool-context-format — turn the JSON-encoded tool context / result that the
 * workbench streams into a human-readable line for the chat thread UI.
 *
 * The workbench stores tool input args as a JSON string on `tool.context`,
 * and tool results as JSON on `tool.summary` for some tools (web_search,
 * list_directory, …). Displaying the raw object in the chat thread is
 * machine-readable but user-hostile — this helper produces a one-line
 * summary plus the original raw payload so the UI can offer a "Show raw"
 * toggle.
 */

import { formatBytes, formatDuration } from './utils';

export interface FormattedContext {
  /** Human-readable summary, e.g. `Searched: "plan verification"`. */
  summary: string;
  /** Original raw text (JSON or otherwise) — render in a "Show raw" toggle. */
  raw: string;
  /**
   * Semantic classification so the UI can render an icon + colour.
   *   'success' — green check, e.g. `✅ Directory found. Top-level: …`
   *   'neutral' — default styling (default if omitted)
   */
  kind?: 'success' | 'neutral';
}

export interface FormattedError {
  /** Short, user-friendly error message, e.g. `Directory '…' does not exist.` */
  message: string;
  /** Optional extra detail (e.g. exit code, file path, line number). */
  detail?: string;
  /** Original raw error text — render in a "Show raw" toggle. */
  raw: string;
}

/**
 * Strip the workbench / august / @ prefixes so the canonical tool name can
 * be matched against the format tables. Mirrors the logic in `tool-labels.ts`.
 */
export function canonicalToolName(name: string): string {
  return (name || '').replace(/^[^:]+:/, '').replace(/^@/, '').replace(/^(august__?|workbench_)/, '');
}

const FILE_OPS = new Set([
  'read_file',
  'read',
  'view_file',
  'write_file',
  'write',
  'write_to_file',
  'edit_file',
  'edit',
  'replace_file_content',
  'multi_replace_file_content',
  'replace_text',
  'create_file',
  'delete_file',
  'delete',
]);

const SEARCH_OPS = new Set([
  'grep_search',
  'grep',
  'search_files',
  'search',
  'august_search',
  'august__search',
]);

const WEB_OPS = new Set([
  'web_search',
  'web_fetch',
  'web',
  'search_web',
  'read_url_content',
  'execute_url',
]);

const MEMORY_OPS = new Set(['remember', 'forget', 'recall', 'memory_write']);

const SUBAGENT_OPS = new Set([
  'spawn_subagent',
  'invoke_subagent',
  'delegate_task',
  'run_team',
]);

const LIST_OPS = new Set(['list_dir', 'list_directory', 'ls']);

const SYSTEM_OPS = new Set([
  'system_info',
  'describe_environment',
]);

const DIAGNOSTIC_OPS = new Set([
  'diagnose_proxy',
  'list_proxy_capabilities',
]);

const AGENT_LIST_OPS = new Set([
  'list_agent_registry',
  'list_agent_jobs',
]);

const AGENT_GET_OPS = new Set(['get_agent_job']);

const ACTIVITY_OPS = new Set(['get_activity']);

function pickString(obj: Record<string, unknown>, keys: string[]): string | undefined {
  for (const k of keys) {
    const v = obj[k];
    if (typeof v === 'string' && v.length > 0) return v;
  }
  return undefined;
}

function truncate(s: string, n: number): string {
  return s.length <= n ? s : `${s.slice(0, n - 1).trimEnd()}…`;
}

function tryParse(json?: string): Record<string, unknown> | null {
  if (!json) return null;
  try {
    const parsed = JSON.parse(json);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>;
    }
  } catch {
    /* not JSON — caller decides what to do */
  }
  return null;
}

/**
 * Format a tool's `context` (input args) as a human-readable line.
 * Returns null only if there is nothing to format.
 */
export function formatToolContext(toolName: string, contextJson?: string): FormattedContext | null {
  if (!contextJson) return null;
  const raw = contextJson;
  const canonical = canonicalToolName(toolName);

  // Try to parse as JSON; fall back to showing the raw text verbatim.
  const parsed = tryParse(raw);

  // File ops
  if (FILE_OPS.has(canonical)) {
    const path = parsed && pickString(parsed, ['filePath', 'file_path', 'path', 'filename', 'file', 'filepath', 'notebook_path', 'target_file']);
    if (path) {
      const verb =
        canonical.startsWith('write') || canonical === 'create_file' ? 'Writing' :
        canonical.startsWith('edit') || canonical.startsWith('replace') ? 'Editing' :
        canonical.startsWith('delete') ? 'Deleting' :
        'Reading';
      return { summary: `${verb} ${path}`, raw };
    }
  }

  // List directory
  if (LIST_OPS.has(canonical)) {
    const path = parsed && pickString(parsed, ['path', 'dir', 'directory', 'filePath', 'file_path']);
    if (path) return { summary: `Listing directory ${path}`, raw };
    return { summary: 'Listing directory', raw };
  }

  // Web search / fetch
  if (WEB_OPS.has(canonical)) {
    const query = parsed && pickString(parsed, ['query', 'q', 'url', 'searchQuery', 'search_query']);
    const maxResults = parsed && (typeof parsed.maxResults === 'number' ? parsed.maxResults : (typeof parsed.maxResults === 'number' ? parsed.maxResults : undefined));
    const verb = canonical === 'web_fetch' || canonical === 'web' || canonical === 'read_url_content' || canonical === 'execute_url'
      ? 'Fetching'
      : 'Searched';
    if (query) {
      const tail = typeof maxResults === 'number' ? ` · ${maxResults} results` : '';
      return { summary: `${verb}: "${query}"${tail}`, raw };
    }
    return { summary: verb === 'Fetching' ? 'Fetching URL' : 'Web request', raw };
  }

  // Grep / search files
  if (SEARCH_OPS.has(canonical)) {
    const pattern = parsed && pickString(parsed, ['pattern', 'query', 'q', 'regex', 'searchPattern', 'search_pattern']);
    const path = parsed && pickString(parsed, ['path', 'dir', 'directory', 'filePath', 'file_path', 'includePattern', 'include_pattern']);
    if (pattern && path) return { summary: `Searching files: "${truncate(pattern, 80)}" in ${path}`, raw };
    if (pattern) return { summary: `Searching files: "${truncate(pattern, 80)}"`, raw };
    return { summary: 'Searching files', raw };
  }

  // Run command / bash
  if (canonical === 'run_command' || canonical === 'bash') {
    const cmd = parsed && pickString(parsed, ['command', 'cmd', 'shell_command', 'shellCommand', 'script']);
    if (cmd) return { summary: `Executing command: ${truncate(cmd, 120)}`, raw };
    return { summary: 'Executing command', raw };
  }

  // Memory ops
  if (MEMORY_OPS.has(canonical)) {
    return { summary: 'Updating memory', raw };
  }

  // Subagent / team spawn — show agent + task summary
  if (SUBAGENT_OPS.has(canonical)) {
    const agentId = parsed && pickString(parsed, ['agentId', 'agent', 'subagentType', 'team']);
    const task = parsed && pickString(parsed, ['task', 'prompt', 'description', 'goal']);
    if (agentId && task) {
      return { summary: `Spawning subagent ${agentId}: "${truncate(task, 100)}"`, raw };
    }
    if (agentId) {
      return { summary: `Spawning subagent ${agentId}`, raw };
    }
    if (task) {
      return { summary: `Spawning subagent: "${truncate(task, 100)}"`, raw };
    }
    return { summary: canonical === 'run_team' ? 'Running team' : 'Spawning subagent', raw };
  }

  // Loading skill
  if (canonical === 'load_skill') {
    const skill = parsed && pickString(parsed, ['skill', 'name', 'skill_name']);
    if (skill) return { summary: `Loading skill ${skill}`, raw };
    return { summary: 'Loading skill', raw };
  }

  // Generic fallback — humanize the canonical name and surface the first
  // scalar arg so the user has a hint of what's being invoked.
  if (parsed) {
    const human = canonical
      .replace(/[_-]+/g, ' ')
      .split(/\s+/)
      .filter(Boolean)
      .map(w => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ') || 'Executing tool';
    const firstScalar = Object.values(parsed).find(v => typeof v === 'string' && v.length > 0) as string | undefined;
    if (firstScalar) {
      return { summary: `${human}: ${truncate(firstScalar, 100)}`, raw };
    }
    return { summary: human, raw };
  }

  // Not JSON — show the raw text as-is (it's already human-readable).
  return { summary: raw, raw };
}

/**
 * Lighter pass for the `result` field. Some tools emit JSON-shaped results
 * (e.g. `web_search` returns `{ results: [...] }`, `list_directory` returns
 * `{ entries: [...] }`). When we recognise the shape, render a friendly
 * summary that includes a preview of the actual contents (file names,
 * top search hits, etc.) rather than just a count. Otherwise return null so
 * the existing text rendering is preserved.
 */
export function formatToolResult(toolName: string, summaryText?: string): FormattedContext | null {
  if (!summaryText) return null;
  const raw = summaryText;
  const canonical = canonicalToolName(toolName);
  const parsed = tryParse(raw);
  if (!parsed) return null;

  // web_search / web_fetch → success with top-hit titles
  if (WEB_OPS.has(canonical)) {
    const results = Array.isArray(parsed.results) ? parsed.results
      : Array.isArray(parsed.hits) ? parsed.hits
      : null;
    if (results) {
      if (results.length === 0) {
        return { summary: 'No results found', raw, kind: 'success' };
      }
      const titles = results
        .map((r: unknown) => {
          if (typeof r === 'string') return r;
          if (r && typeof r === 'object') {
            const o = r as Record<string, unknown>;
            const t = pickString(o, ['title', 'name']);
            if (t) return t;
            const u = pickString(o, ['url', 'link']);
            if (u) return u;
          }
          return '';
        })
        .filter(Boolean)
        .slice(0, 3);
      const head = titles.length > 0 ? `: ${titles.join(' · ')}` : '';
      const more = results.length - titles.length;
      const tail = more > 0 ? ` (+${more} more)` : '';
      return {
        summary: `Found ${results.length} result${results.length === 1 ? '' : 's'}${head}${tail}`,
        raw,
        kind: 'success',
      };
    }
  }

  // list_directory → success with top-level names
  if (LIST_OPS.has(canonical)) {
    const entries = Array.isArray(parsed.entries) ? parsed.entries
      : Array.isArray(parsed.files) ? parsed.files
      : Array.isArray(parsed.items) ? parsed.items
      : null;
    if (entries) {
      if (entries.length === 0) {
        return { summary: 'Directory is empty', raw, kind: 'success' };
      }
      const names = entries
        .map((e: unknown): string => {
          if (typeof e === 'string') return e;
          if (e && typeof e === 'object') {
            const o = e as Record<string, unknown>;
            const n = pickString(o, ['name', 'path', 'filename', 'file', 'entry']);
            if (n) return n;
          }
          return '';
        })
        .filter(Boolean)
        .slice(0, 5);
      const more = entries.length - names.length;
      const head = names.length > 0 ? `: ${names.join(', ')}` : '';
      const tail = more > 0 ? ` (+${more} more)` : '';
      const verb = parsed.truncated ? 'Found at least ' : 'Found ';
      return {
        summary: `${verb}${entries.length} item${entries.length === 1 ? '' : 's'}${head}${tail}`,
        raw,
        kind: 'success',
      };
    }
  }

  // search_files / grep → success with match count
  if (SEARCH_OPS.has(canonical)) {
    const matches = Array.isArray(parsed.matches) ? parsed.matches
      : Array.isArray(parsed.results) ? parsed.results
      : Array.isArray(parsed.files) ? parsed.files
      : null;
    if (matches) {
      if (matches.length === 0) {
        return { summary: 'No matches found', raw, kind: 'success' };
      }
      return {
        summary: `${matches.length} match${matches.length === 1 ? '' : 'es'} found`,
        raw,
        kind: 'success',
      };
    }
  }

  // system_info / describe_environment → success with platform + memory + uptime
  if (SYSTEM_OPS.has(canonical)) {
    // Backend wraps the real payload in `{ ok, result }` for system_info,
    // and returns `{ generatedAt, environment: {...} }` for describe_environment.
    // Unwrap whichever shape is present.
    const sys = (parsed.result && typeof parsed.result === 'object' ? parsed.result : parsed) as Record<string, unknown>;
    if (canonical === 'system_info' && sys && typeof sys === 'object') {
      const platform = pickString(sys, ['platform']) ?? '?';
      const arch = pickString(sys, ['arch']);
      const cpus = Array.isArray(sys.cpus) ? sys.cpus.length : (typeof sys.cpus === 'number' ? sys.cpus : undefined);
      const totalMem = typeof sys.totalmem === 'number' ? sys.totalmem : undefined;
      const uptime = typeof sys.uptime === 'number' ? sys.uptime : undefined;
      const parts = [platform];
      if (arch) parts.push(arch);
      if (typeof cpus === 'number') parts.push(`${cpus} CPU${cpus === 1 ? '' : 's'}`);
      if (typeof totalMem === 'number') parts.push(formatBytes(totalMem));
      if (typeof uptime === 'number') parts.push(`up ${formatDuration(uptime * 1000)}`);
      return { summary: `System info: ${parts.join(' · ')}`, raw, kind: 'success' };
    }
    if (canonical === 'describe_environment' && sys && typeof sys === 'object') {
      const env = (sys.environment && typeof sys.environment === 'object' ? sys.environment : sys) as Record<string, unknown>;
      const envName = pickString(env, ['name', 'env', 'environment']) ?? 'environment';
      const version = pickString(env, ['version']);
      const head = version ? `${envName} ${version}` : envName;
      return { summary: `Environment: ${head}`, raw, kind: 'success' };
    }
  }

  // diagnose_proxy / list_proxy_capabilities
  if (DIAGNOSTIC_OPS.has(canonical)) {
    if (canonical === 'diagnose_proxy') {
      const status = pickString(parsed, ['status']) ?? 'unknown';
      const capsCount = Array.isArray(parsed.capabilities) ? parsed.capabilities.length : 0;
      const actCount = Array.isArray(parsed.activity) ? parsed.activity.length : 0;
      const actionsCount = Array.isArray(parsed.recommendedActions) ? parsed.recommendedActions.length : 0;
      if (status === 'ok') {
        return {
          summary: `Diagnostics: ok · ${capsCount} capabilities · ${actCount} recent events`,
          raw,
          kind: 'success',
        };
      }
      return {
        summary: `Diagnostics: ${status} · ${actionsCount} action${actionsCount === 1 ? '' : 's'} recommended`,
        raw,
        kind: 'neutral',
      };
    }
    if (canonical === 'list_proxy_capabilities') {
      const caps = Array.isArray(parsed.capabilities) ? parsed.capabilities
        : Array.isArray(parsed) ? parsed
        : null;
      if (caps) {
        const names = caps
          .map((c: unknown): string => {
            if (typeof c === 'string') return c;
            if (c && typeof c === 'object') {
              const o = c as Record<string, unknown>;
              return pickString(o, ['name', 'id', 'tool']) ?? '';
            }
            return '';
          })
          .filter(Boolean)
          .slice(0, 3);
        const more = caps.length - names.length;
        const head = names.length > 0 ? `: ${names.join(', ')}` : '';
        const tail = more > 0 ? ` (+${more} more)` : '';
        return {
          summary: `${caps.length} capabilit${caps.length === 1 ? 'y' : 'ies'}${head}${tail}`,
          raw,
          kind: 'success',
        };
      }
    }
  }

  // list_agent_registry / list_agent_jobs
  if (AGENT_LIST_OPS.has(canonical)) {
    if (canonical === 'list_agent_registry') {
      const agents = Array.isArray(parsed.agents) ? parsed.agents : null;
      if (agents) {
        const roles = agents
          .map((a: unknown): string => {
            if (a && typeof a === 'object') {
              const o = a as Record<string, unknown>;
              return pickString(o, ['role', 'type', 'name']) ?? '';
            }
            return '';
          })
          .filter(Boolean);
        const uniqueRoles = Array.from(new Set(roles)).slice(0, 3);
        const roleSummary = uniqueRoles.length > 0 ? ` (${uniqueRoles.join(', ')})` : '';
        const more = agents.length - uniqueRoles.length;
        const tail = more > 0 ? ` +${more} more` : '';
        return {
          summary: `${agents.length} agent${agents.length === 1 ? '' : 's'} registered${roleSummary}${tail}`,
          raw,
          kind: 'success',
        };
      }
    }
    if (canonical === 'list_agent_jobs') {
      const jobs = Array.isArray(parsed.jobs) ? parsed.jobs : null;
      if (jobs) {
        const counts: Record<string, number> = {};
        for (const j of jobs) {
          if (j && typeof j === 'object') {
            const status = pickString(j as Record<string, unknown>, ['status']) ?? 'unknown';
            counts[status] = (counts[status] ?? 0) + 1;
          }
        }
        const parts = Object.entries(counts).map(([s, n]) => `${n} ${s}`);
        const head = parts.length > 0 ? ` · ${parts.join(' · ')}` : '';
        return {
          summary: `${jobs.length} job${jobs.length === 1 ? '' : 's'}${head}`,
          raw,
          kind: 'success',
        };
      }
    }
  }

  // get_agent_job
  if (AGENT_GET_OPS.has(canonical)) {
    const id = pickString(parsed, ['id', 'job_id', 'jobId']);
    const status = pickString(parsed, ['status']) ?? 'unknown';
    const startedAt = typeof parsed.startedAt === 'number' ? parsed.startedAt : undefined;
    const completedAt = typeof parsed.completedAt === 'number' ? parsed.completedAt : undefined;
    const duration =
      typeof startedAt === 'number' && typeof completedAt === 'number'
        ? formatDuration(completedAt - startedAt)
        : undefined;
    const idStr = id ? id.slice(0, 8) : '?';
    const durStr = duration ? ` · ${duration}` : '';
    return {
      summary: `Job ${idStr} · ${status}${durStr}`,
      raw,
      kind: status === 'completed' || status === 'done' || status === 'ok' ? 'success' : 'neutral',
    };
  }

  // get_activity
  if (ACTIVITY_OPS.has(canonical)) {
    const events = Array.isArray(parsed.events) ? parsed.events
      : Array.isArray(parsed.activity) ? parsed.activity
      : null;
    if (events) {
      if (events.length === 0) {
        return { summary: 'No recent activity', raw, kind: 'success' };
      }
      const first = events[0];
      let firstSummary = '';
      if (typeof first === 'string') firstSummary = first;
      else if (first && typeof first === 'object') {
        const o = first as Record<string, unknown>;
        firstSummary =
          pickString(o, ['message', 'summary', 'event', 'description']) ??
          pickString(o, ['type', 'kind', 'action']) ??
          '';
      }
      const tail = firstSummary ? `: "${truncate(firstSummary, 80)}"` : '';
      return {
        summary: `${events.length} recent event${events.length === 1 ? '' : 's'}${tail}`,
        raw,
        kind: 'success',
      };
    }
  }

  // Generic `status: ok` payload (common in workbench responses)
  const status = pickString(parsed, ['status']);
  if (status === 'ok' || status === 'success') {
    const message = pickString(parsed, ['message', 'detail']);
    if (message) {
      return { summary: message, raw, kind: 'success' };
    }
    return { summary: 'Completed successfully', raw, kind: 'success' };
  }

  return null;
}

/**
 * Parse a tool's error string into a structured `FormattedError` so the UI
 * can render a prominent ❌ block instead of dumping raw JSON.
 *
 * Handles three shapes:
 *   1. Plain-text error string (most common) — trimmed and returned as-is.
 *   2. JSON object with a `message`/`error`/`reason` field — that field is
 *      surfaced as `message`, optional `code`/`exit_code` as `detail`.
 *   3. JSON object without a recognisable message — fall back to a generic
 *      "Tool failed" message with the raw text in the toggle.
 */
export function formatToolError(toolName: string, errorText?: string): FormattedError | null {
  if (!errorText) return null;
  const raw = errorText;
  const parsed = tryParse(raw);

  if (parsed) {
    const message = pickString(parsed, ['message', 'error', 'detail', 'reason', 'description', 'msg']);
    const detailParts: string[] = [];
    const code = pickString(parsed, ['code', 'error_code']);
    const exitCode = typeof parsed.exit_code === 'number'
      ? String(parsed.exit_code)
      : typeof parsed.exitCode === 'number'
        ? String(parsed.exitCode)
        : undefined;
    const path = pickString(parsed, ['path', 'filePath', 'file_path', 'file', 'directory']);
    if (code) detailParts.push(`code: ${code}`);
    if (exitCode) detailParts.push(`exit: ${exitCode}`);
    if (path) detailParts.push(path);
    if (message) {
      return { message, detail: detailParts.length ? detailParts.join(' · ') : undefined, raw };
    }
    // JSON-shaped error without a recognisable message — still parsed, but
    // surface a generic message and let the user expand for the raw shape.
    return { message: `${canonicalToolName(toolName) || 'Tool'} failed`, raw };
  }

  // Plain-text error — clean up trailing whitespace/newlines.
  const cleaned = raw.trim();
  if (!cleaned) return null;
  return { message: cleaned, raw };
}

/* v4.3 — Brain Activity tab: live feed of brain events with chip filters + pause. */
import { useEffect, useMemo, useRef, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Loader2, Pause, Play, Sparkles } from 'lucide-react';
import { getBrainEvents, openBrainEventStream, type BrainEvent } from '@/api/api-client';

const CATEGORIES: Array<{ key: BrainEvent['category'] | 'all'; label: string; color: string }> = [
  { key: 'all',          label: 'All',           color: 'text-foreground' },
  { key: 'consolidation', label: 'Consolidation', color: 'text-info' },
  { key: 'heuristic',     label: 'Heuristics',    color: 'text-success' },
  { key: 'delta_engine',  label: 'Delta Engine',  color: 'text-warning' },
  { key: 'review',        label: 'Review',        color: 'text-primary' },
  { key: 'skill_genesis', label: 'Skill Genesis', color: 'text-accent' },
];

const CATEGORY_COLOR: Record<string, string> = Object.fromEntries(
  CATEGORIES.map((c) => [c.key, c.color]),
);

export function BrainActivityTab() {
  const [activeChip, setActiveChip] = useState<BrainEvent['category'] | 'all'>('all');
  const [paused, setPaused] = useState(false);
  const [liveEvents, setLiveEvents] = useState<BrainEvent[]>([]);

  const eventsQ = useQuery({
    queryKey: ['brain-events', activeChip],
    queryFn: () => getBrainEvents(200),
  });

  // SSE: when not paused, push events into liveEvents (capped).
  // We don't filter live events by chip — UI does it client-side.
  const streamRef = useRef<EventSource | null>(null);
  useEffect(() => {
    const es = openBrainEventStream();
    streamRef.current = es;
    es.onmessage = (ev: MessageEvent) => {
      if (paused) return;
      try {
        const event = JSON.parse(ev.data) as BrainEvent;
        setLiveEvents((prev) => [event, ...prev].slice(0, 200));
      } catch {
        // Ignore malformed frames
      }
    };
    return () => {
      es.close();
      streamRef.current = null;
    };
  }, [paused]);

  // Merge recent + live. Live takes precedence on dedupe by id.
  const merged = useMemo(() => {
    const seen = new Set<string>();
    const combined: BrainEvent[] = [];
    for (const e of liveEvents) {
      if (!seen.has(e.id)) {
        seen.add(e.id);
        combined.push(e);
      }
    }
    for (const e of eventsQ.data ?? []) {
      if (!seen.has(e.id)) {
        seen.add(e.id);
        combined.push(e);
      }
    }
    return combined;
  }, [eventsQ.data, liveEvents]);

  const filtered = useMemo(() => {
    if (activeChip === 'all') return merged;
    return merged.filter((e) => e.category === activeChip);
  }, [merged, activeChip]);

  if (eventsQ.isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Toolbar: status indicator + pause + filter chips */}
      <div className="flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-1.5 text-xs">
          <span
            className={`size-2 rounded-full ${paused ? 'bg-muted-foreground' : 'bg-success animate-pulse'}`}
            aria-hidden
          />
          <span className="text-muted-foreground">{paused ? 'Paused' : 'Live'}</span>
        </div>
        <button
          type="button"
          onClick={() => setPaused((p) => !p)}
          aria-label={paused ? 'Resume' : 'Pause'}
          data-testid="brain-activity-pause"
          className="px-2 py-1 text-xs rounded border border-white/[0.06] hover:bg-white/[0.06] flex items-center gap-1"
        >
          {paused ? <Play className="size-3" /> : <Pause className="size-3" />}
          <span>{paused ? 'Resume' : 'Pause'}</span>
        </button>

        <div className="flex flex-wrap gap-1.5 ml-2" role="group" aria-label="Filter by category">
          {CATEGORIES.map((c) => (
            <button
              key={c.key}
              type="button"
              onClick={() => setActiveChip(c.key)}
              data-testid={`brain-chip-${c.key}`}
              className={`px-2 py-1 text-xs rounded-full border transition ${
                activeChip === c.key
                  ? 'bg-primary/20 border-primary text-foreground'
                  : 'border-white/[0.06] text-muted-foreground hover:bg-white/[0.03]'
              }`}
            >
              {c.label}
            </button>
          ))}
        </div>
      </div>

      {/* Event feed */}
      {filtered.length === 0 ? (
        <div className="text-xs text-muted-foreground text-center py-12 border border-dashed border-white/[0.06] rounded-lg">
          <Sparkles className="size-4 inline-block mr-2 opacity-40" />
          No brain activity yet — start chatting to see the brain learn.
        </div>
      ) : (
        <ul
          className="space-y-1 max-h-[60vh] overflow-y-auto"
          data-testid="brain-activity-feed"
        >
          {filtered.map((e) => (
            <li
              key={e.id}
              data-testid="brain-event"
              data-category={e.category}
              className="bg-card/60 border border-white/[0.06] rounded-md p-2 text-xs flex gap-3"
            >
              <span className="text-muted-foreground/70 font-mono shrink-0 w-20">
                {new Date(e.at).toLocaleTimeString()}
              </span>
              <span
                className={`shrink-0 w-24 truncate text-[10px] uppercase tracking-wide ${CATEGORY_COLOR[e.category] ?? 'text-muted-foreground'}`}
              >
                {e.category.replace('_', ' ')}
              </span>
              <span className="flex-1">{e.summary}</span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

/* v3 — System Health tab: per-phase status board */
import { useEffect, useState } from 'react';
import { Clock, Heart } from 'lucide-react';

interface LayerInfo {
  layer: string;
  flag: string;
  flagValue: boolean;
  status: 'on & healthy' | 'on & failing' | 'off' | 'not shipped';
  detail: string;
  lastCheckAt: string;
}

interface HealthData {
  phases: LayerInfo[];
}

const STATUS_COLOR: Record<string, string> = {
  'on & healthy': 'text-success',
  'on & failing': 'text-danger',
  off: 'text-muted-foreground',
  'not shipped': 'text-muted-foreground',
};

const DOT_COLOR: Record<string, string> = {
  'on & healthy': 'bg-success',
  'on & failing': 'bg-danger',
  off: 'bg-muted-foreground',
  'not shipped': 'bg-muted',
};

const API_BASE = '/api/brain';

export function SystemHealthTab() {
  const [data, setData] = useState<HealthData | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    const fetchData = async () => {
      try {
        const resp = await fetch(`${API_BASE}/health`);
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        const json = await resp.json();
        if (!cancelled) setData(json);
      } catch (e) {
        if (!cancelled) setError((e as Error).message);
      }
    };
    void fetchData();
    const id = setInterval(() => { void fetchData(); }, 5000);
    return () => {
      cancelled = true;
      clearInterval(id);
    };
  }, []);

  if (error) {
    return <div className="p-4 text-danger">Error loading health: {error}</div>;
  }
  if (!data) {
    return (
      <div className="p-8 text-center text-muted-foreground flex items-center justify-center gap-2">
        <Clock className="size-4 animate-spin" /> Loading…
      </div>
    );
  }

  const allHealthy = data.phases.every((p) => p.status === 'on & healthy' || p.status === 'off');

  return (
    <div className="space-y-2">
      <div className="grid grid-cols-12 gap-3 px-4 py-2 text-xs font-medium text-muted-foreground uppercase tracking-wider">
        <span className="col-span-4">Phase / Layer</span>
        <span className="col-span-2">Flag</span>
        <span className="col-span-2">Status</span>
        <span className="col-span-4">Detail</span>
      </div>
      {data.phases.map((p) => (
        <div
          key={p.flag}
          className="grid grid-cols-12 gap-3 items-start px-4 py-2.5 bg-card rounded-lg border border-border text-sm"
        >
          <span className="col-span-4 font-medium">{p.layer}</span>
          <code className="col-span-2 text-xs text-muted-foreground">{p.flag}</code>
          <span
            className={`col-span-2 inline-flex items-center gap-1 text-xs font-medium ${
              STATUS_COLOR[p.status] ?? 'text-muted-foreground'
            }`}
          >
            <span className={`size-1.5 rounded-full ${DOT_COLOR[p.status] ?? 'bg-muted'}`} />
            {p.status}
          </span>
          <div className="col-span-4 text-xs text-muted-foreground">
            <p>{p.detail}</p>
            <p className="text-[10px] mt-0.5">
              checked {new Date(p.lastCheckAt).toLocaleTimeString()}
            </p>
          </div>
        </div>
      ))}
      {allHealthy && (
        <div className="p-3 bg-success/10 text-success text-xs rounded-lg flex items-center gap-2">
          <Heart className="size-3.5" /> All cognitive layers are healthy.
        </div>
      )}
    </div>
  );
}

/**
 * CalendarCard — Inline week-view calendar for voice commands.
 *
 * Spec: docs/superpowers/specs/2026-06-30-voice-subagent-provider-overhaul-design.md
 * Uses VoiceCommandCardProps so it plugs into the registry.
 *
 * Data sources:
 * - August internal events via GET /api/calendar/internal
 * - External events via useMcpTools (filters tools matching calendar.* patterns)
 * - If no MCP calendar server configured, shows only internal events with a hint
 */

import { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, X } from 'lucide-react';
import { useMcpTools, type McpTool } from '@/hooks/useMcpTools';
import type { VoiceCommandCardProps } from '@/api/voice/registry';

// ── Types ──────────────────────────────────────────────────────────────────

interface CalendarEvent {
  id: string;
  title: string;
  date: string; // ISO date YYYY-MM-DD
  kind: 'task' | 'reminder' | 'scheduled_chat' | 'external';
  source: 'internal' | 'mcp';
}

// ── Date helpers ───────────────────────────────────────────────────────────

function getWeekDates(weekOffset: number): Date[] {
  const now = new Date();
  const dayOfWeek = now.getDay();
  // Monday-based week (Mon=1, Tue=2, ..., Sun=0 via JS getDay)
  const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(now);
  monday.setDate(now.getDate() + mondayOffset + weekOffset * 7);
  monday.setHours(0, 0, 0, 0);

  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    return d;
  });
}

function dateKey(d: Date): string {
  return d.toISOString().slice(0, 10);
}

function formatDate(d: Date): string {
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function isToday(d: Date): boolean {
  return dateKey(d) === dateKey(new Date());
}

const DAY_NAMES = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

// ── Card component ─────────────────────────────────────────────────────────

export function CalendarCard({ onDismiss }: VoiceCommandCardProps) {
  const [weekOffset, setWeekOffset] = useState(0);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { tools } = useMcpTools();

  const hasCalendarMcp = tools.some(
    (t: McpTool) =>
      t.name.includes('calendar') ||
      t.name.includes('gcal') ||
      t.name.includes('events'),
  );

  // Fetch internal events on mount.
  useEffect(() => {
    fetch('/api/calendar/internal')
      .then(r => r.json())
      .then(data => {
        setEvents(data.events ?? []);
        setLoading(false);
      })
      .catch((_err) => {
        setError('Failed to load events');
        setLoading(false);
      });
  }, []);

  const weekDates = getWeekDates(weekOffset);
  const weekStart = formatDate(weekDates[0]);
  const weekEnd = formatDate(weekDates[6]);

  const eventsByDay = new Map<string, CalendarEvent[]>();
  for (const ev of events) {
    const key = ev.date;
    if (!eventsByDay.has(key)) eventsByDay.set(key, []);
    eventsByDay.get(key)!.push(ev);
  }

  const _todayKey = dateKey(new Date());

  return (
    <div
      data-slot="calendar-card"
      className="rounded-lg border border-border bg-card p-4 space-y-3 max-w-2xl"
    >
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <CalendarIcon className="size-4 text-muted-foreground" />
          <span className="text-sm font-semibold text-foreground">
            {weekStart} — {weekEnd}
          </span>
        </div>
        <button
          onClick={onDismiss}
          className="p-1 rounded hover:bg-muted text-muted-foreground"
          aria-label="Close calendar"
        >
          <X className="size-4" />
        </button>
      </div>

      {/* Loading state */}
      {loading && (
        <div className="text-xs text-muted-foreground py-4 text-center">
          Loading events…
        </div>
      )}

      {/* Error state */}
      {error && (
        <div className="text-xs text-red-500 py-2 text-center">{error}</div>
      )}

      {/* Week grid */}
      {!loading && !error && (
        <div className="grid grid-cols-7 gap-1">
          {DAY_NAMES.map(name => (
            <div
              key={name}
              className="text-[10px] uppercase text-muted-foreground text-center font-semibold py-1"
            >
              {name}
            </div>
          ))}
          {weekDates.map(d => {
            const key = dateKey(d);
            const dayEvents = eventsByDay.get(key) ?? [];
            const today = isToday(d);

            return (
              <div
                key={key}
                className={`rounded p-1.5 min-h-[60px] border text-xs ${
                  today
                    ? 'border-primary bg-primary/5'
                    : 'border-border bg-background'
                }`}
              >
                <div
                  className={`text-[11px] font-medium mb-1 ${
                    today ? 'text-primary' : 'text-foreground'
                  }`}
                >
                  {d.getDate()}
                </div>
                {dayEvents.slice(0, 3).map(ev => (
                  <div
                    key={ev.id}
                    className={`text-[10px] leading-tight truncate rounded px-0.5 mb-0.5 ${
                      ev.source === 'internal'
                        ? 'bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300'
                        : 'bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-300'
                    }`}
                    title={ev.title}
                  >
                    {ev.title}
                  </div>
                ))}
                {dayEvents.length > 3 && (
                  <div className="text-[9px] text-muted-foreground">
                    +{dayEvents.length - 3} more
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Week navigation */}
      <div className="flex items-center justify-between pt-1">
        <button
          type="button"
          onClick={() => setWeekOffset(o => o - 1)}
          className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"
        >
          <ChevronLeft className="size-3" />
          <span>Prev week</span>
        </button>

        <button
          type="button"
          onClick={() => setWeekOffset(0)}
          className="text-xs text-muted-foreground hover:text-foreground"
        >
          Today
        </button>

        <button
          type="button"
          onClick={() => setWeekOffset(o => o + 1)}
          className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"
        >
          <span>Next week</span>
          <ChevronRight className="size-3" />
        </button>
      </div>

      {/* No MCP calendar hint */}
      {!loading && !error && !hasCalendarMcp && (
        <div className="text-[11px] text-muted-foreground text-center border-t border-border pt-2 mt-1">
          No internal events. Connect a calendar MCP server to see external events.
        </div>
      )}
    </div>
  );
}

import { useEffect, useRef, useState, useLayoutEffect, useCallback, type RefObject } from 'react';
import { createPortal } from 'react-dom';
import { Paperclip, AtSign, Mic, Send, StopCircle, X, type LucideIcon } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import {
  FOCUS_COMPOSER_EVENT,
  INSERT_COMPOSER_TEXT_EVENT,
} from '@/api/ui-events';

interface ModelItem {
  id: string;
  name: string;
  provider: string;
  contextWindow: number;
  isFree?: boolean;
  supportsReasoning?: boolean;
  supportsThinking?: boolean;
}

interface ToolOption {
  name: string;
  desc: string;
}

interface CommandOption {
  name: string;
  desc: string;
}

interface ChatComposerProps {
  input: string;
  attachments: Array<{ name: string; size: string }>;
  voiceActive: boolean;
  showToolsDropdown: boolean;
  showCommandsDropdown: boolean;
  streaming: boolean;
  currentModel: ModelItem | null;
  selectedModel: ModelItem | null;
  models: ModelItem[];
  visibleModels: ModelItem[];
  modelsLoading: boolean;
  effort: 'low' | 'medium' | 'high' | 'max';
  pct: number;
  estTokens: number;
  maxContext: number;
  taRef: RefObject<HTMLTextAreaElement | null>;
  fileInputRef: RefObject<HTMLInputElement | null>;
  sessionId: string | null;
  tools: ToolOption[];
  commands: CommandOption[];
  onInputChange: (value: string) => void;
  onKey: (event: React.KeyboardEvent<HTMLTextAreaElement>) => void;
  onInsertText: (text: string) => void;
  onToggleToolsDropdown: (open: boolean) => void;
  onToggleCommandsDropdown: (open: boolean) => void;
  onRemoveAttachment: (index: number) => void;
  onOpenFilePicker: () => void;
  onStartVoiceInput: () => void;
  onRefreshModels: (refresh?: boolean) => void;
  onEditModels: () => void;
  onSelectModel: (model: ModelItem | null) => void;
  onEffortChange: (value: 'low' | 'medium' | 'high' | 'max') => void;
  onSend: () => void;
  onStop: () => void;
  onToggleModelVisibility: (modelId: string) => void;
  onSetModelVisibilityOpen: (open: boolean) => void;
  onSetSessionModel: (sessionId: string | null | undefined, modelId: string, provider: string) => void;
}

export function ChatComposer({
  input,
  attachments,
  voiceActive,
  showToolsDropdown,
  showCommandsDropdown,
  streaming,
  currentModel,
  selectedModel,
  models,
  visibleModels,
  modelsLoading,
  effort,
  pct,
  estTokens,
  maxContext,
  sessionId,
  taRef,
  fileInputRef,
  tools,
  commands,
  onInputChange,
  onKey,
  onInsertText,
  onToggleToolsDropdown,
  onToggleCommandsDropdown,
  onRemoveAttachment,
  onOpenFilePicker,
  onStartVoiceInput,
  onRefreshModels,
  onEditModels,
  onSelectModel,
  onEffortChange,
  onSend,
  onStop,
  onToggleModelVisibility,
  onSetModelVisibilityOpen,
  onSetSessionModel,
}: ChatComposerProps) {
  // Task 5: respond to LLM-driven UI events that target the composer.
  useEffect(() => {
    if (typeof window === 'undefined') return;
    const focusHandler = () => {
      // Defer focus to next frame so we don't fight the React render cycle.
      requestAnimationFrame(() => {
        taRef.current?.focus();
      });
    };
    const insertHandler = (event: Event) => {
      const ce = event as CustomEvent<{ text: string }>;
      const text = ce.detail?.text;
      if (typeof text === 'string' && text.length > 0) {
        onInsertText(text);
        taRef.current?.focus();
      }
    };
    window.addEventListener(FOCUS_COMPOSER_EVENT, focusHandler);
    window.addEventListener(INSERT_COMPOSER_TEXT_EVENT, insertHandler);
    return () => {
      window.removeEventListener(FOCUS_COMPOSER_EVENT, focusHandler);
      window.removeEventListener(INSERT_COMPOSER_TEXT_EVENT, insertHandler);
    };
  }, [taRef, onInsertText]);

  // v4 §16.2: Auto-grow textarea — value-driven, not event-driven
  const MAX_H = 360;
  const resizeTextarea = useCallback(() => {
    const el = taRef.current;
    if (!el) return;
    el.style.height = 'auto';
    const next = Math.min(el.scrollHeight, MAX_H);
    el.style.height = next + 'px';
    el.style.overflowY = el.scrollHeight > MAX_H ? 'auto' : 'hidden';
  }, [taRef]);

  useLayoutEffect(() => { resizeTextarea(); }, [input, resizeTextarea]);

  return (
    <>
      {showToolsDropdown && (
        <div className="absolute bottom-full mb-2 left-2 z-10 w-64 bg-card border border-border shadow-2xl rounded-xl p-1.5 space-y-0.5 animate-in fade-in slide-in-from-bottom-2 duration-150">
          <div className="px-2 py-1 text-[10px] text-muted-foreground uppercase font-semibold">Mention Tool</div>
          {tools.map((t) => (
            <button
              key={t.name}
              onClick={() => {
                onInsertText(t.name);
                onToggleToolsDropdown(false);
                onToggleCommandsDropdown(false);
              }}
              className="w-full text-left rounded-md px-2.5 py-1.5 text-xs text-foreground/80 hover:bg-muted hover:text-foreground transition flex items-center justify-between"
            >
              <span className="font-mono font-medium text-primary">{t.name}</span>
              <span className="text-[10px] text-muted-foreground">{t.desc}</span>
            </button>
          ))}
        </div>
      )}

      {showCommandsDropdown && (
        <div className="absolute bottom-full mb-2 left-2 z-10 w-64 bg-card border border-border shadow-2xl rounded-xl p-1.5 space-y-0.5 animate-in fade-in slide-in-from-bottom-2 duration-150">
          <div className="px-2 py-1 text-[10px] text-muted-foreground uppercase font-semibold">Commands & Tools</div>
          {commands.filter(c => !input || c.name.startsWith(input)).map((c) => (
            <button
              key={c.name}
              onClick={() => {
                onInsertText(c.name);
                onToggleCommandsDropdown(false);
                onToggleToolsDropdown(false);
              }}
              className="w-full text-left rounded-md px-2.5 py-1.5 text-xs text-foreground/80 hover:bg-muted hover:text-foreground transition flex items-center justify-between"
            >
              <span className="font-mono font-medium text-warning">{c.name}</span>
              <span className="text-[10px] text-muted-foreground">{c.desc}</span>
            </button>
          ))}
        </div>
      )}

      <div className={cn(
        'w-full min-w-0 rounded-2xl border bg-card shadow-sm transition focus-within:ring-2 focus-within:ring-primary/40 focus-within:border-primary overflow-visible',
        'border-border',
      )}>
        {voiceActive ? (
          <div className="h-[128px] w-full flex flex-col items-center justify-center bg-background/90 backdrop-blur-sm space-y-2 text-foreground">
            <div className="flex items-center gap-1">
              <span className="w-1 h-4 bg-primary rounded animate-pulse" />
              <span className="w-1 h-6 bg-primary rounded animate-pulse" style={{ animationDelay: '150ms' }} />
              <span className="w-1 h-8 bg-primary rounded animate-pulse" style={{ animationDelay: '300ms' }} />
              <span className="w-1 h-5 bg-primary rounded animate-pulse" style={{ animationDelay: '450ms' }} />
              <span className="w-1 h-3 bg-primary rounded animate-pulse" style={{ animationDelay: '600ms' }} />
            </div>
            <span className="text-xs font-semibold tracking-wide text-primary animate-pulse">August is listening…</span>
          </div>
        ) : (
          <>
            {attachments.length > 0 && (
              <div className="flex flex-wrap gap-1.5 p-2 bg-muted/20 border-b border-border">
                {attachments.map((file, i) => (
                  <div key={i} className="flex items-center gap-1.5 px-2 py-1 rounded-lg bg-muted border border-border text-[10.5px] font-mono">
                    <span className="truncate max-w-[150px]">{file.name}</span>
                    <button
                      onClick={() => onRemoveAttachment(i)}
                      className="p-0.5 hover:bg-background rounded text-muted-foreground hover:text-foreground transition"
                      aria-label={`Remove ${file.name}`}
                    >
                      <X className="size-2.5" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            <textarea
              ref={taRef}
              value={input}
              onChange={(e) => onInputChange(e.target.value)}
              onKeyDown={onKey}
              placeholder={streaming ? 'Type to queue your next message…' : (currentModel ? `Message ${currentModel.name}…` : 'Message August…')}
              rows={1}
              className="w-full resize-none bg-transparent px-4 pt-3 pb-1.5 bubble-body outline-none placeholder:text-muted-foreground"
              style={{ minHeight: '64px', maxHeight: '360px' }}
            />
          </>
        )}

        <div className="flex flex-wrap items-center justify-between gap-x-2 gap-y-1 px-1.5 pb-1.5">
          <div className="flex items-center text-muted-foreground">
            <ToolBtn Icon={Paperclip} label="Attach file" onClick={onOpenFilePicker} />
            <ToolBtn Icon={AtSign} label="Mention tool" onClick={() => { onToggleToolsDropdown(!showToolsDropdown); onToggleCommandsDropdown(false); }} />
            <ToolBtn Icon={Mic} label="Voice input" onClick={onStartVoiceInput} />
          </div>
          <div className="flex items-center gap-2">
            <ModelDropdown
              models={models}
              visibleModels={visibleModels}
              loading={modelsLoading}
              selected={selectedModel}
              onRefresh={() => onRefreshModels(true)}
              onEditModels={onEditModels}
              onSelect={onSelectModel}
              onToggleModelVisibility={onToggleModelVisibility}
              onSetModelVisibilityOpen={onSetModelVisibilityOpen}
              onSetSessionModel={onSetSessionModel}
              sessionId={sessionId}
            />
            {selectedModel?.supportsReasoning && (
              <EffortDropdown value={effort} onChange={onEffortChange} />
            )}

            {streaming ? (
              <Button onClick={onStop} size="sm" variant="outline">
                <StopCircle className="size-3" /> Stop
              </Button>
            ) : (
              <Button onClick={onSend} disabled={!input.trim() && attachments.length === 0} size="sm">
                <Send className="size-3" />
                Send
                <kbd className="ml-1 rounded bg-muted/30 border border-border/30 px-1 text-[11px] font-mono">↵</kbd>
              </Button>
            )}
          </div>
        </div>
      </div>

      <div className="flex items-center justify-end mt-1 px-1">
        <ContextRing pct={pct} estTokens={estTokens} maxContext={maxContext} modelName={currentModel?.name} />
      </div>
    </>
  );
}

function ToolBtn({ Icon, label, onClick }: { Icon: LucideIcon; label: string; onClick?: () => void }) {
  return (
    <button
      onClick={onClick}
      className="p-1.5 rounded-lg hover:bg-muted hover:text-foreground transition text-muted-foreground"
      title={label}
    >
      <Icon className="size-4" />
    </button>
  );
}

function ModelDropdown({
